#!/usr/bin/env python3
"""Targeted guardrail checks for high-risk blueprint contracts.

This script complements JSON Schema compilation with a few higher-order checks
that are easy to regress during spec edits:

- embedded read models staying aligned with their durable source contracts
- customer-safe workspace projections not leaking internal state
- route/action/task projections rejecting empty identifiers and anchors
- grouped task shells preserving one deterministic bucket per group code
"""

from __future__ import annotations

import json
import re
import sys
from pathlib import Path
from typing import Any, Iterable


