class GuardFailure(Exception):
    pass


def load_schema(name: str) -> dict[str, Any]:
    return json.loads((SCHEMAS / name).read_text())


def load_json(name: str) -> dict[str, Any]:
    return json.loads((ROOT / name).read_text())


def load_doc(name: str) -> str:
    return (ROOT / name).read_text()


def ensure(condition: bool, message: str) -> None:
    if not condition:
        raise GuardFailure(message)


def ensure_doc_terms(text: str, doc_name: str, terms: list[str], message: str) -> None:
    lowered = text.lower()
    missing = [term for term in terms if term not in lowered]
    ensure(not missing, f"{doc_name} {message} Missing: {', '.join(missing)}")


def extract_numbered_markdown_items(text: str) -> list[int]:
    return [int(match.group(1)) for match in re.finditer(r"(?m)^(\d+)\. ", text)]


def parse_markdown_table_after_heading(text: str, heading: str) -> tuple[list[str], list[list[str]]]:
    start = text.find(heading)
    ensure(start != -1, f"Missing `{heading}` heading.")

    table_lines: list[str] = []
    for line in text[start + len(heading) :].splitlines():
        stripped = line.strip()
        if not stripped:
            if table_lines:
                break
            continue
        if stripped.startswith("## "):
            break
        if stripped.startswith("|"):
            table_lines.append(stripped)
            continue
        if table_lines:
            break

    ensure(len(table_lines) >= 2, f"`{heading}` must contain a markdown table.")
    header = [cell.strip() for cell in table_lines[0].strip("|").split("|")]
    rows = [[cell.strip() for cell in line.strip("|").split("|")] for line in table_lines[2:]]
    return header, rows


def extract_markdown_section(text: str, heading: str) -> str:
    match = re.search(rf"(?ms)^## {re.escape(heading)}\n(.*?)(?=^## |\Z)", text)
    ensure(match is not None, f"Missing `## {heading}` section.")
    return match.group(1)


def extract_readme_schema_inventory_line(text: str) -> str:
    for line in text.splitlines():
        if line.startswith("- JSON schemas + sample payloads in `schemas/`, including "):
            return line
    raise GuardFailure("README must include the schema inventory bullet under `## What you get`.")


def resolve_readme_path_token(token: str) -> Path | None:
    if " " in token or token.startswith(("http://", "https://")):
        return None
    if "<" in token or ">" in token or "*" in token:
        return None
    if "/" not in token and not token.endswith((".md", ".json", ".py", ".txt")):
        return None
    repo_root = ROOT.parent
    return repo_root / token if token.startswith("Algorithm/") else ROOT / token


def extract_embedded_repo_paths(token: str) -> list[str]:
    return re.findall(r"\b(?:Algorithm|schemas|scripts|tools)/[A-Za-z0-9_./<>*-]+\b", token)


def extract_repo_python_script_paths(token: str) -> list[str]:
    return re.findall(r"\bAlgorithm/(?:scripts|tools)/[A-Za-z0-9_./-]+\.py\b", token)


def markdown_code_tokens(cell: str) -> list[str]:
    return re.findall(r"`([^`]+)`", cell)


def build_constraint_traceability_doc_cache(
    register: dict[str, Any],
    *,
    preload: dict[str, str] | None = None,
) -> dict[str, str | None]:
    cache: dict[str, str | None] = {}
    if preload:
        cache.update(preload)
    for entry in register.get("entries", []):
        if not isinstance(entry, dict):
            continue
        for group_name in TRACEABILITY_REF_GROUPS:
            for ref in entry.get(group_name, []):
                if not isinstance(ref, dict):
                    continue
                path = ref.get("path")
                if not isinstance(path, str) or path in cache:
                    continue
                target = ROOT / path
                cache[path] = target.read_text() if target.exists() else None
    return cache


def check_live_constraint_traceability_register() -> None:
    schema = load_schema("constraint_traceability_register.schema.json")
    properties = schema["properties"]
    ensure(
        properties["contract_version"].get("const") == "CONSTRAINT_TRACEABILITY_REGISTER_V1",
        "constraint_traceability_register schema must pin contract_version to CONSTRAINT_TRACEABILITY_REGISTER_V1",
    )
    ensure(
        properties["register_scope"].get("const") == "LIVE_CONSTRAINTS_ONLY",
        "constraint_traceability_register schema must pin register_scope to LIVE_CONSTRAINTS_ONLY",
    )
    ensure(
        properties["historical_note_boundary"].get("const")
        == "HISTORICAL_NOTES_LIVE_IN_FORENSIC_DOCS_ONLY",
        "constraint_traceability_register schema must pin the live-vs-forensic boundary constant",
    )
    ensure(
        properties["coherence_update_policy"].get("const")
        == "AUTHORITATIVE_AND_DOWNSTREAM_REFS_MOVE_IN_SAME_CHANGESET",
        "constraint_traceability_register schema must pin same-change-set coherence updates",
    )
    ensure(
        properties["entries"].get("minItems") == 8,
        "constraint_traceability_register schema must require at least eight live named constraints",
    )
    traceability_ref_required = schema["$defs"]["traceabilityRef"]["required"]
    ensure(
        traceability_ref_required == ["path", "kind", "required_terms"],
        "constraint_traceability_register traceabilityRef must require path, kind, and required_terms",
    )
    constraint_entry_required = schema["$defs"]["constraintEntry"]["required"]
    ensure(
        constraint_entry_required
        == [
            "constraint_id",
            "constraint_name",
            "constraint_family",
            "status",
            "architectural_rationale",
            "prompt_stage_refs",
            "authoritative_refs",
            "enforcement_refs",
            "downstream_refs",
            "example_refs",
        ],
        "constraint_traceability_register constraintEntry must require the full live traceability spine",
    )
    kind_enum = schema["$defs"]["traceabilityRef"]["properties"]["kind"]["enum"]
    ensure(
        "REGISTER" in kind_enum and "FORENSIC_HISTORY" in kind_enum,
        "constraint_traceability_register traceabilityRef.kind must retain REGISTER and FORENSIC_HISTORY coverage",
    )

    register = json.loads(load_doc("constraint_traceability_register.json"))
    entries = register.get("entries")
    ensure(
        isinstance(entries, list),
        "constraint_traceability_register.json must keep entries as an array",
    )

    doc_cache = build_constraint_traceability_doc_cache(
        register,
        preload={
            "constraint_coverage_index.md": load_doc("constraint_coverage_index.md"),
            "README.md": load_doc("README.md"),
            "architecture_coherence_guardrails.md": load_doc("architecture_coherence_guardrails.md"),
            "implementation_conventions.md": load_doc("implementation_conventions.md"),
            "test_vectors.md": load_doc("test_vectors.md"),
        },
    )

    seen_ids: set[str] = set()
    ordered_ids: list[str] = []
    entry_by_id: dict[str, dict[str, Any]] = {}
    for entry in entries:
        ensure(isinstance(entry, dict), "constraint_traceability_register.json entries must be objects")
        constraint_id = entry.get("constraint_id")
        constraint_name = entry.get("constraint_name")
        ensure(isinstance(constraint_id, str), "Each live constraint entry must keep a string constraint_id")
        ensure(
            constraint_id not in seen_ids,
            f"constraint_traceability_register.json duplicates `{constraint_id}`",
        )
        seen_ids.add(constraint_id)
        ordered_ids.append(constraint_id)
        entry_by_id[constraint_id] = entry
        ensure(isinstance(constraint_name, str) and constraint_name, f"{constraint_id} must keep constraint_name")
        lowered_name = constraint_name.lower()
        ensure(
            not any(phrase in lowered_name for phrase in CONSTRAINT_TRACEABILITY_STALE_NAME_PHRASES),
            f"{constraint_id} must describe a live constraint, not stale defect phrasing",
        )

        for group_name in TRACEABILITY_REF_GROUPS:
            refs = entry.get(group_name, [])
            ensure(
                isinstance(refs, list),
                f"{constraint_id} must keep `{group_name}` as an array",
            )
            for ref in refs:
                ensure(isinstance(ref, dict), f"{constraint_id} `{group_name}` refs must be objects")
                path = ref.get("path")
                kind = ref.get("kind")
                required_terms = ref.get("required_terms")
                ensure(isinstance(path, str), f"{constraint_id} `{group_name}` refs must keep a string path")
                ensure(
                    kind in TRACEABILITY_ALLOWED_KINDS_BY_GROUP[group_name],
                    f"{constraint_id} `{group_name}` uses unsupported kind `{kind}`",
                )
                ensure(
                    not (kind == "FORENSIC_HISTORY" and group_name not in TRACEABILITY_ALLOWED_HISTORY_GROUPS),
                    f"{constraint_id} must keep FORENSIC_HISTORY refs out of `{group_name}`",
                )
                ensure(
                    not (kind == "FORENSIC_HISTORY" and path not in CONSTRAINT_TRACEABILITY_ALLOWED_HISTORICAL_PATHS),
                    f"{constraint_id} must keep FORENSIC_HISTORY refs limited to the forensic history docs",
                )
                ensure(
                    isinstance(required_terms, list),
                    f"{constraint_id} `{group_name}` ref `{path}` must keep required_terms[]",
                )
                text = doc_cache.get(path)
                ensure(text is not None, f"{constraint_id} references missing traceability path `{path}`")
                lowered = text.lower()
                missing_terms = [
                    term for term in required_terms if not isinstance(term, str) or term.lower() not in lowered
                ]
                ensure(
                    not missing_terms,
                    f"{constraint_id} `{group_name}` ref `{path}` is missing required traceability terms {missing_terms}",
                )

        enforcement_refs = entry.get("enforcement_refs", [])
        ensure(
            any(
                isinstance(ref, dict)
                and ref.get("kind") == "VALIDATOR"
                and ref.get("path") == "scripts/validate_contracts.py"
                for ref in enforcement_refs
            ),
            f"{constraint_id} must include scripts/validate_contracts.py in enforcement_refs",
        )
        ensure(
            any(
                isinstance(ref, dict)
                and ref.get("kind") == "FORENSIC_GUARD"
                and ref.get("path") == "tools/forensic_contract_guard.py"
                for ref in enforcement_refs
            ),
            f"{constraint_id} must include tools/forensic_contract_guard.py in enforcement_refs",
        )

        historical_refs = entry.get("historical_context_refs", [])
        ensure(
            isinstance(historical_refs, list),
            f"{constraint_id}.historical_context_refs must stay a list when present",
        )
        for ref in historical_refs:
            ensure(
                isinstance(ref, dict),
                f"{constraint_id}.historical_context_refs refs must be objects",
            )
            path = ref.get("path")
            ensure(
                isinstance(path, str) and path in CONSTRAINT_TRACEABILITY_ALLOWED_HISTORICAL_PATHS,
                f"{constraint_id}.historical_context_refs must stay limited to the forensic history docs",
            )

    ensure(
        ordered_ids == sorted(ordered_ids),
        "constraint_traceability_register.json entries must stay ordered by constraint_id",
    )

    coverage_index = doc_cache["constraint_coverage_index.md"] or ""
    header, rows = parse_markdown_table_after_heading(
        coverage_index, CONSTRAINT_TRACEABILITY_REGISTER_HEADING
    )
    ensure(
        header == CONSTRAINT_TRACEABILITY_REGISTER_COLUMNS,
        "constraint_coverage_index.md must keep the active named constraint register header",
    )

    row_by_id: dict[str, dict[str, str]] = {}
    for row in rows:
        ensure(
            len(row) == len(CONSTRAINT_TRACEABILITY_REGISTER_COLUMNS),
            f"constraint_coverage_index.md has malformed active named constraint row: {row}",
        )
        row_map = dict(zip(CONSTRAINT_TRACEABILITY_REGISTER_COLUMNS, row))
        id_tokens = markdown_code_tokens(row_map["ID"])
        constraint_id = id_tokens[0] if id_tokens else row_map["ID"].strip()
        ensure(
            constraint_id not in row_by_id,
            f"constraint_coverage_index.md duplicates `{constraint_id}` in the active named constraint register",
        )
        row_by_id[constraint_id] = row_map

    ensure(
        list(row_by_id) == ordered_ids,
        "constraint_coverage_index.md must list the same active constraint ids in the same order as constraint_traceability_register.json",
    )

    for constraint_id in ordered_ids:
        entry = entry_by_id[constraint_id]
        row = row_by_id[constraint_id]
        ensure(
            row["Active constraint"] == entry.get("constraint_name"),
            f"{constraint_id} name drift between constraint_traceability_register.json and constraint_coverage_index.md",
        )
        ensure(
            bool(row["Architectural rationale"].strip()),
            f"{constraint_id} must keep a non-empty architectural rationale in constraint_coverage_index.md",
        )

        expected_authoritative = [
            ref["path"] for ref in entry.get("authoritative_refs", []) if isinstance(ref, dict)
        ]
        expected_enforcement = [
            ref["path"] for ref in entry.get("enforcement_refs", []) if isinstance(ref, dict)
        ]
        expected_downstream_and_examples = [
            *[ref["path"] for ref in entry.get("downstream_refs", []) if isinstance(ref, dict)],
            *[ref["path"] for ref in entry.get("example_refs", []) if isinstance(ref, dict)],
        ]

        ensure(
            markdown_code_tokens(row["Authoritative boundary"]) == expected_authoritative,
            f"{constraint_id} authoritative-boundary paths must mirror constraint_traceability_register.json exactly",
        )
        ensure(
            markdown_code_tokens(row["Machine enforcement"]) == expected_enforcement,
            f"{constraint_id} machine-enforcement paths must mirror constraint_traceability_register.json exactly",
        )
        ensure(
            markdown_code_tokens(row["Downstream and example propagation"])
            == expected_downstream_and_examples,
            f"{constraint_id} downstream/example paths must mirror constraint_traceability_register.json exactly",
        )


def find_rule_by_const(rules: Iterable[dict[str, Any]], field: str, value: Any) -> dict[str, Any] | None:
    for rule in rules:
        rule_if = rule.get("if", {})
        properties = rule_if.get("properties", {})
        field_schema = properties.get(field, {})
        if field_schema.get("const") == value:
            return rule
    return None


def find_rule_by_enum(rules: Iterable[dict[str, Any]], field: str, values: list[Any]) -> dict[str, Any] | None:
    for rule in rules:
        rule_if = rule.get("if", {})
        properties = rule_if.get("properties", {})
        field_schema = properties.get(field, {})
        if field_schema.get("enum") == values:
            return rule
    return None


def find_rule_by_contains_const(rules: Iterable[dict[str, Any]], field: str, value: Any) -> dict[str, Any] | None:
    for rule in rules:
        rule_if = rule.get("if", {})
        properties = rule_if.get("properties", {})
        field_schema = properties.get(field, {})
        if field_schema.get("contains", {}).get("const") == value:
            return rule
    return None


def schema_uses_ref(fragment: Any, ref: str) -> bool:
    if not isinstance(fragment, dict):
        return False
    if fragment.get("$ref") == ref:
        return True
    for keyword in ("allOf", "anyOf", "oneOf"):
        for child in fragment.get(keyword, []):
            if schema_uses_ref(child, ref):
                return True
    return False


def check_min_length_fields(schema: dict[str, Any], fields: list[str], schema_name: str) -> None:
    for field in fields:
        ensure(
            schema["properties"][field].get("minLength") == 1,
            f"{schema_name}.{field} must reject empty strings",
        )


def check_shell_dominance_contract_binding(
    schema: dict[str, Any],
    schema_name: str,
    *,
    expected_question_surface: str | None = None,
    expected_action_surface: str | None = None,
    expected_queue_policy: str | None = None,
    expected_support_surfaces: list[str] | None = None,
) -> None:
    ensure(
        "dominance_contract" in schema["required"],
        f"{schema_name} must require `dominance_contract` for machine-readable single-question single-action discipline",
    )
    fragment = schema["properties"]["dominance_contract"]
    ensure(
        schema_uses_ref(fragment, "https://taxat.dev/schemas/shell_dominance_contract.schema.json"),
        f"{schema_name}.dominance_contract must stay bound to shell_dominance_contract.schema.json",
    )

    local_props: dict[str, Any] = {}
    if isinstance(fragment, dict):
        local_props.update(fragment.get("properties", {}))
        for child in fragment.get("allOf", []):
            if isinstance(child, dict):
                local_props.update(child.get("properties", {}))

    if expected_question_surface is not None:
        ensure(
            local_props.get("dominant_question_surface_code", {}).get("const") == expected_question_surface,
            f"{schema_name}.dominance_contract.dominant_question_surface_code must stay `{expected_question_surface}`",
        )
    if expected_action_surface is not None:
        ensure(
            local_props.get("dominant_action_surface_code", {}).get("const") == expected_action_surface,
            f"{schema_name}.dominance_contract.dominant_action_surface_code must stay `{expected_action_surface}`",
        )
    if expected_queue_policy is not None:
        ensure(
            local_props.get("supplemental_queue_policy", {}).get("const") == expected_queue_policy,
            f"{schema_name}.dominance_contract.supplemental_queue_policy must stay `{expected_queue_policy}`",
        )
    if expected_support_surfaces is not None:
        ensure(
            local_props.get("promoted_support_surface_code_or_null", {}).get("enum") == [*expected_support_surfaces, None],
            f"{schema_name}.dominance_contract promoted-support enum must stay {expected_support_surfaces} plus null",
        )


