def collect_nested_properties(fragment: dict[str, Any]) -> dict[str, Any]:
    properties: dict[str, Any] = {}
    if not isinstance(fragment, dict):
        return properties
    properties.update(fragment.get("properties", {}))
    for keyword in ("allOf", "anyOf", "oneOf"):
        for child in fragment.get(keyword, []):
            if isinstance(child, dict):
                properties.update(collect_nested_properties(child))
    return properties


