def check_deterministic_golden_pack() -> None:
    schema = load_schema("deterministic_golden_pack.schema.json")
    ensure(
        schema.get("additionalProperties") is False,
        "deterministic_golden_pack must reject unknown fields",
    )
    for field in [
        "golden_pack_id",
        "artifact_type",
        "contract_version",
        "golden_pack_hash",
        "candidate_identity_hash",
        "candidate_identity_contract",
        "schema_bundle_hash",
        "config_bundle_hash",
        "canonical_serialization_policy",
        "exact_decimal_policy",
        "null_slot_policy",
        "replay_comparison_policy",
        "state_transition_policy",
        "cadence_policy",
        "module_fixtures",
        "state_transition_fixtures",
        "replay_fixtures",
        "cadence_fixtures",
    ]:
        ensure(field in schema["required"], f"deterministic_golden_pack must require `{field}`")
    ensure(
        schema["properties"]["artifact_type"].get("const") == "DeterministicGoldenPack",
        "deterministic_golden_pack.artifact_type must stay DeteministicGoldenPack",
    )
    ensure(
        schema["properties"]["contract_version"].get("const") == "DETERMINISTIC_GOLDEN_PACK_V1",
        "deterministic_golden_pack.contract_version must stay DETERMINISTIC_GOLDEN_PACK_V1",
    )
    ensure(
        schema_uses_ref(
            schema["properties"]["candidate_identity_contract"],
            "https://taxat.dev/schemas/release_candidate_identity_contract.schema.json",
        ),
        "deterministic_golden_pack.candidate_identity_contract must stay bound to release_candidate_identity_contract.schema.json",
    )
    for field, expected in (
        ("canonical_serialization_policy", "CANONICAL_JSON_SORTED_KEYS_UTF8"),
        ("exact_decimal_policy", "EXACT_DECIMAL_STRING_NO_LOCALE_NO_EXPONENT"),
        ("null_slot_policy", "EXPLICIT_NULL_SLOTS_RETAINED_IN_ORDERED_PAYLOADS"),
        (
            "replay_comparison_policy",
            "GOLDEN_FIXTURES_BIND_CANDIDATE_SCHEMA_SCOPE_AND_EXPECTED_HASHES",
        ),
        (
            "state_transition_policy",
            "STATE_MACHINE_FIXTURES_REQUIRE_NAMED_PREVIOUS_AND_CURRENT_STATE",
        ),
        (
            "cadence_policy",
            "DETERMINISTIC_RETRY_AND_RECONCILIATION_CADENCE_NO_RANDOM_JITTER",
        ),
    ):
        ensure(
            schema["properties"][field].get("const") == expected,
            f"deterministic_golden_pack.{field} must stay `{expected}`",
        )
    for field in [
        "module_fixtures",
        "state_transition_fixtures",
        "replay_fixtures",
        "cadence_fixtures",
    ]:
        ensure(
            schema["properties"][field].get("minItems") == 1,
            f"deterministic_golden_pack.{field} must require at least one fixture row",
        )

    module_fixture = schema["$defs"]["moduleFixture"]
    for field in [
        "fixture_id",
        "module_code",
        "artifact_family",
        "scope_binding_hash",
        "canonical_payload_hash",
        "expected_null_field_paths",
        "expected_decimal_fields",
        "expected_ordered_array_fields",
        "fixture_binding_policy",
    ]:
        ensure(
            field in module_fixture["required"],
            f"deterministic_golden_pack moduleFixture must require `{field}`",
        )
    ensure(
        module_fixture["properties"]["fixture_binding_policy"].get("const")
        == "CANDIDATE_SCHEMA_SCOPE_BOUND",
        "deterministic_golden_pack moduleFixture.fixture_binding_policy must freeze candidate/schema/scope binding",
    )
    ensure(
        module_fixture["properties"]["expected_null_field_paths"].get("minItems") == 1,
        "deterministic_golden_pack moduleFixture.expected_null_field_paths must require explicit null coverage",
    )

    decimal_expectation = schema["$defs"]["decimalFieldExpectation"]
    ensure(
        decimal_expectation["properties"]["decimal_value"].get("pattern")
        == "^-?(0|[1-9]\\d*)(\\.\\d+)?$",
        "deterministic_golden_pack decimal expectations must keep exact-decimal string form",
    )

    ordered_array_expectation = schema["$defs"]["orderedArrayExpectation"]
    ensure(
        ordered_array_expectation["properties"]["ordering_policy"].get("const")
        == "PRESERVE_DECLARED_ORDER",
        "deterministic_golden_pack orderedArrayExpectation.ordering_policy must preserve declared order",
    )

    state_transition_fixture = schema["$defs"]["stateTransitionFixture"]
    ensure(
        schema_uses_ref(
            state_transition_fixture["properties"]["state_transition_contract"],
            "https://taxat.dev/schemas/state_transition_contract.schema.json",
        ),
        "deterministic_golden_pack stateTransitionFixture.state_transition_contract must stay bound to state_transition_contract.schema.json",
    )
    ensure(
        state_transition_fixture["properties"]["transition_binding_policy"].get("const")
        == "NAMED_STATE_MACHINE_TUPLE_AND_EVENT",
        "deterministic_golden_pack stateTransitionFixture.transition_binding_policy must freeze named state-machine tuples",
    )

    replay_fixture = schema["$defs"]["replayFixture"]
    ensure(
        replay_fixture["properties"]["comparison_binding_policy"].get("const")
        == "CANDIDATE_SCHEMA_SCOPE_AND_HASH_BOUND",
        "deterministic_golden_pack replayFixture.comparison_binding_policy must freeze candidate/schema/scope/hash binding",
    )

    cadence_fixture = schema["$defs"]["cadenceFixture"]
    ensure(
        cadence_fixture["properties"]["jitter_policy"].get("const") == "NONE",
        "deterministic_golden_pack cadenceFixture.jitter_policy must stay NONE",
    )


