def check_restore_privacy_reconciliation_contract() -> None:
    schema = load_schema("restore_privacy_reconciliation_contract.schema.json")
    ensure(schema.get("additionalProperties") is False, "restore_privacy_reconciliation_contract must reject unknown fields")
    ensure(
        schema["required"]
        == [
            "contract_version",
            "reconciliation_contract_hash",
            "checkpoint_ref",
            "restore_drill_ref",
            "reconciliation_scope_policy",
            "resurrected_data_posture",
            "resurrected_subject_count_or_null",
            "privacy_reconciliation_state",
            "privacy_reconciliation_outcome_ref",
            "compensating_re_erasure_state",
            "compensating_re_erasure_workflow_ref_or_null",
            "compensating_re_erasure_audit_ref_or_null",
            "legal_hold_ref_or_null",
            "proof_preservation_basis_ref_or_null",
            "authority_ambiguity_ref_or_null",
            "audit_chain_continuity_state",
            "audit_chain_continuity_ref",
            "replay_limitation_state",
            "enquiry_limitation_state",
            "reopen_access_state",
            "reconciliation_decided_at_or_null",
            "re_erasure_completed_at_or_null",
        ],
        "restore_privacy_reconciliation_contract must require the full BE-82 restore privacy reconciliation tuple",
    )
    ensure(
        schema["properties"]["contract_version"].get("const") == "RESTORE_PRIVACY_RECONCILIATION_V1",
        "restore_privacy_reconciliation_contract.contract_version must stay RESTORE_PRIVACY_RECONCILIATION_V1",
    )
    ensure(
        schema["properties"]["reconciliation_scope_policy"].get("const")
        == "RESTORE_REQUIRES_PRIVACY_LIMITATION_AND_RE_ERASURE_PROOF",
        "restore_privacy_reconciliation_contract.reconciliation_scope_policy must freeze the restore privacy scope",
    )
    ensure(
        schema["properties"]["privacy_reconciliation_state"].get("enum")
        == [
            "PENDING_RECONCILIATION",
            "RECONCILED_NO_COMPENSATION_REQUIRED",
            "COMPENSATING_RE_ERASURE_REQUIRED",
            "COMPENSATING_RE_ERASURE_IN_PROGRESS",
            "RECONCILED_WITH_COMPENSATING_RE_ERASURE",
            "BLOCKED_LEGAL_HOLD",
            "BLOCKED_PROOF_PRESERVATION",
            "BLOCKED_AUTHORITY_AMBIGUITY",
        ],
        "restore_privacy_reconciliation_contract.privacy_reconciliation_state must keep the typed reconciliation lifecycle",
    )
    ensure(
        schema["properties"]["compensating_re_erasure_state"].get("enum")
        == ["NOT_REQUIRED", "REQUIRED_PENDING", "IN_PROGRESS", "COMPLETED", "BLOCKED"],
        "restore_privacy_reconciliation_contract.compensating_re_erasure_state must keep the typed compensating re-erasure lifecycle",
    )
    ensure(
        schema["properties"]["replay_limitation_state"].get("enum") == ["VERIFIED", "LIMITED_RECONCILED", "FAILED"]
        and schema["properties"]["enquiry_limitation_state"].get("enum")
        == ["VERIFIED", "LIMITED_RECONCILED", "FAILED"],
        "restore_privacy_reconciliation_contract limitation states must keep verified, limited, and failed postures",
    )
    ensure(
        schema["properties"]["reopen_access_state"].get("enum") == ["BLOCKED", "LIMITED", "READY_FOR_REOPEN"],
        "restore_privacy_reconciliation_contract.reopen_access_state must keep the typed reopen boundary",
    )

    pending_rule = find_rule_by_const(schema["allOf"], "privacy_reconciliation_state", "PENDING_RECONCILIATION")
    ensure(pending_rule is not None, "restore_privacy_reconciliation_contract missing PENDING_RECONCILIATION guard")
    pending_then = pending_rule["then"]["properties"]
    ensure(
        pending_then["resurrected_data_posture"].get("const") == "UNKNOWN_UNTIL_RECONCILED"
        and pending_then["compensating_re_erasure_state"].get("const") == "NOT_REQUIRED"
        and pending_then["reopen_access_state"].get("const") == "BLOCKED",
        "restore_privacy_reconciliation_contract pending posture must stay unknown and blocked",
    )

    no_comp_rule = find_rule_by_const(
        schema["allOf"], "privacy_reconciliation_state", "RECONCILED_NO_COMPENSATION_REQUIRED"
    )
    ensure(
        no_comp_rule is not None,
        "restore_privacy_reconciliation_contract missing RECONCILED_NO_COMPENSATION_REQUIRED guard",
    )
    no_comp_then = no_comp_rule["then"]["properties"]
    ensure(
        no_comp_then["resurrected_data_posture"].get("const") == "NONE_DETECTED"
        and no_comp_then["resurrected_subject_count_or_null"].get("const") == 0
        and no_comp_then["compensating_re_erasure_state"].get("const") == "NOT_REQUIRED"
        and no_comp_then["audit_chain_continuity_state"].get("const") == "VERIFIED"
        and no_comp_then["replay_limitation_state"].get("const") == "VERIFIED"
        and no_comp_then["enquiry_limitation_state"].get("const") == "VERIFIED"
        and no_comp_then["reopen_access_state"].get("const") == "READY_FOR_REOPEN",
        "restore_privacy_reconciliation_contract no-resurrection posture must be fully verified and reopen-ready",
    )

    required_rule = find_rule_by_const(
        schema["allOf"], "privacy_reconciliation_state", "COMPENSATING_RE_ERASURE_REQUIRED"
    )
    ensure(
        required_rule is not None,
        "restore_privacy_reconciliation_contract missing COMPENSATING_RE_ERASURE_REQUIRED guard",
    )
    required_then = required_rule["then"]["properties"]
    ensure(
        required_then["compensating_re_erasure_state"].get("const") == "REQUIRED_PENDING"
        and required_then["compensating_re_erasure_workflow_ref_or_null"].get("type") == "string"
        and required_then["compensating_re_erasure_audit_ref_or_null"].get("type") == "string"
        and required_then["reopen_access_state"].get("const") == "BLOCKED",
        "restore_privacy_reconciliation_contract pending compensating re-erasure must require workflow and audit refs and keep reopen blocked",
    )

    in_progress_rule = find_rule_by_const(
        schema["allOf"], "privacy_reconciliation_state", "COMPENSATING_RE_ERASURE_IN_PROGRESS"
    )
    ensure(
        in_progress_rule is not None,
        "restore_privacy_reconciliation_contract missing COMPENSATING_RE_ERASURE_IN_PROGRESS guard",
    )
    in_progress_then = in_progress_rule["then"]["properties"]
    ensure(
        in_progress_then["compensating_re_erasure_state"].get("const") == "IN_PROGRESS"
        and in_progress_then["compensating_re_erasure_workflow_ref_or_null"].get("type") == "string"
        and in_progress_then["compensating_re_erasure_audit_ref_or_null"].get("type") == "string"
        and in_progress_then["reopen_access_state"].get("const") == "BLOCKED",
        "restore_privacy_reconciliation_contract in-progress compensating re-erasure must keep workflow, audit, and blocked reopen posture",
    )

    completed_rule = find_rule_by_const(
        schema["allOf"], "privacy_reconciliation_state", "RECONCILED_WITH_COMPENSATING_RE_ERASURE"
    )
    ensure(
        completed_rule is not None,
        "restore_privacy_reconciliation_contract missing RECONCILED_WITH_COMPENSATING_RE_ERASURE guard",
    )
    completed_then = completed_rule["then"]["properties"]
    ensure(
        completed_then["compensating_re_erasure_state"].get("const") == "COMPLETED"
        and completed_then["audit_chain_continuity_state"].get("const") == "VERIFIED"
        and completed_then["replay_limitation_state"].get("const") == "VERIFIED"
        and completed_then["enquiry_limitation_state"].get("const") == "VERIFIED"
        and completed_then["reopen_access_state"].get("const") == "READY_FOR_REOPEN"
        and completed_then["re_erasure_completed_at_or_null"].get("type") == "string",
        "restore_privacy_reconciliation_contract completed compensating re-erasure must stay fully verified with a completion timestamp",
    )

    for state, blocker_field in [
        ("BLOCKED_LEGAL_HOLD", "legal_hold_ref_or_null"),
        ("BLOCKED_PROOF_PRESERVATION", "proof_preservation_basis_ref_or_null"),
        ("BLOCKED_AUTHORITY_AMBIGUITY", "authority_ambiguity_ref_or_null"),
    ]:
        blocked_rule = find_rule_by_const(schema["allOf"], "privacy_reconciliation_state", state)
        ensure(blocked_rule is not None, f"restore_privacy_reconciliation_contract missing {state} guard")
        blocked_then = blocked_rule["then"]["properties"]
        ensure(
            blocked_then["compensating_re_erasure_state"].get("const") == "BLOCKED"
            and blocked_then[blocker_field].get("type") == "string"
            and blocked_then["replay_limitation_state"].get("const") == "LIMITED_RECONCILED"
            and blocked_then["enquiry_limitation_state"].get("const") == "LIMITED_RECONCILED"
            and blocked_then["reopen_access_state"].get("const") == "LIMITED",
            f"restore_privacy_reconciliation_contract {state} must keep its blocker ref, limited limitation posture, and limited reopen state",
        )

    not_required_rule = find_rule_by_const(schema["allOf"], "compensating_re_erasure_state", "NOT_REQUIRED")
    ensure(
        not_required_rule is not None,
        "restore_privacy_reconciliation_contract missing NOT_REQUIRED reverse guard",
    )
    ensure(
        not_required_rule["then"]["properties"]["compensating_re_erasure_workflow_ref_or_null"].get("type") == "null"
        and not_required_rule["then"]["properties"]["compensating_re_erasure_audit_ref_or_null"].get("type") == "null"
        and not_required_rule["then"]["properties"]["re_erasure_completed_at_or_null"].get("type") == "null",
        "restore_privacy_reconciliation_contract compensating_re_erasure_state=NOT_REQUIRED must clear workflow, audit, and completion refs",
    )

    audit_failed_rule = find_rule_by_const(schema["allOf"], "audit_chain_continuity_state", "FAILED")
    ensure(
        audit_failed_rule is not None,
        "restore_privacy_reconciliation_contract missing audit_chain_continuity_state=FAILED reverse guard",
    )
    ensure(
        audit_failed_rule["then"]["properties"]["reopen_access_state"].get("const") == "BLOCKED",
        "restore_privacy_reconciliation_contract audit continuity failure must force reopen_access_state=BLOCKED",
    )

    for field in ["replay_limitation_state", "enquiry_limitation_state"]:
        failed_rule = next(
            (
                candidate
                for candidate in schema["allOf"]
                if any(
                    branch.get("properties", {}).get(field, {}).get("const") == "FAILED"
                    for branch in candidate.get("if", {}).get("anyOf", [])
                    if isinstance(branch, dict)
                )
            ),
            None,
        )
        ensure(
            failed_rule is not None,
            f"restore_privacy_reconciliation_contract missing {field}=FAILED reverse guard",
        )
        ensure(
            failed_rule["then"]["properties"]["reopen_access_state"].get("const") == "BLOCKED",
            f"restore_privacy_reconciliation_contract {field}=FAILED must force reopen_access_state=BLOCKED",
        )

    for field, expected_state in [
        ("legal_hold_ref_or_null", "BLOCKED_LEGAL_HOLD"),
        ("proof_preservation_basis_ref_or_null", "BLOCKED_PROOF_PRESERVATION"),
        ("authority_ambiguity_ref_or_null", "BLOCKED_AUTHORITY_AMBIGUITY"),
    ]:
        blocker_rule = next(
            (
                candidate
                for candidate in schema["allOf"]
                if candidate.get("if", {}).get("properties", {}).get(field, {}).get("type") == "string"
            ),
            None,
        )
        ensure(
            blocker_rule is not None,
            f"restore_privacy_reconciliation_contract missing reverse guard for {field}",
        )
        ensure(
            blocker_rule["then"]["properties"]["privacy_reconciliation_state"].get("const") == expected_state,
            f"restore_privacy_reconciliation_contract non-null {field} must force privacy_reconciliation_state={expected_state}",
        )


