def check_execution_mode_boundary_contract_binding(
    schema: dict[str, Any],
    schema_name: str,
    *,
    field_name: str = "execution_mode_boundary_contract",
    expected_run_kind: str | None = None,
    expected_execution_posture: str | None = None,
    expected_legal_effect_boundary: str | None = None,
) -> None:
    ensure(
        field_name in schema["required"],
        f"{schema_name} must require `{field_name}` for explicit live-vs-modeled execution boundary discipline",
    )
    fragment = schema["properties"][field_name]
    ensure(
        schema_uses_ref(
            fragment,
            "https://taxat.dev/schemas/execution_mode_boundary_contract.schema.json",
        ),
        f"{schema_name}.{field_name} must stay bound to execution_mode_boundary_contract.schema.json",
    )

    local_props: dict[str, Any] = {}
    if isinstance(fragment, dict):
        local_props.update(fragment.get("properties", {}))
        for child in fragment.get("allOf", []):
            if isinstance(child, dict):
                local_props.update(child.get("properties", {}))

    if expected_run_kind is not None:
        ensure(
            local_props.get("run_kind", {}).get("const") == expected_run_kind,
            f"{schema_name}.{field_name}.run_kind must stay `{expected_run_kind}`",
        )
    if expected_execution_posture is not None:
        ensure(
            local_props.get("execution_posture", {}).get("const") == expected_execution_posture,
            f"{schema_name}.{field_name}.execution_posture must stay `{expected_execution_posture}`",
        )
    if expected_legal_effect_boundary is not None:
        ensure(
            local_props.get("legal_effect_boundary", {}).get("const") == expected_legal_effect_boundary,
            f"{schema_name}.{field_name}.legal_effect_boundary must stay `{expected_legal_effect_boundary}`",
        )


def check_schema_reader_window_contract() -> None:
    schema = load_schema("schema_reader_window_contract.schema.json")
    ensure(
        schema["required"]
        == [
            "contract_version",
            "compatibility_window_ref",
            "writer_schema_bundle_hash",
            "supported_reader_schema_bundle_hashes",
            "protected_historical_schema_bundle_hashes",
            "window_state",
            "historical_manifest_policy",
            "destructive_change_policy",
            "rollback_boundary_policy",
            "fail_forward_policy",
            "replay_restore_policy",
        ],
        "schema_reader_window_contract must require the full FE-47 reader-window contract",
    )
    ensure(
        schema.get("additionalProperties") is False,
        "schema_reader_window_contract must set additionalProperties=false",
    )
    properties = schema["properties"]
    ensure(
        properties["contract_version"].get("const") == "SCHEMA_READER_WINDOW_CONTRACT_V1",
        "schema_reader_window_contract.contract_version must stay SCHEMA_READER_WINDOW_CONTRACT_V1",
    )
    ensure(
        properties["historical_manifest_policy"].get("const")
        == "FROZEN_MANIFESTS_REQUIRE_RECORDED_BUNDLE_OR_COMPATIBLE_READER",
        "schema_reader_window_contract.historical_manifest_policy must freeze frozen-manifest compatibility posture",
    )
    ensure(
        properties["destructive_change_policy"].get("const")
        == "DESTRUCTIVE_CHANGE_BLOCKED_UNTIL_WINDOW_CLOSED",
        "schema_reader_window_contract.destructive_change_policy must freeze expand-then-contract discipline",
    )
    ensure(
        properties["rollback_boundary_policy"].get("const")
        == "ROLLBACK_ALLOWED_ONLY_WHILE_PREVIOUS_READERS_SUPPORTED",
        "schema_reader_window_contract.rollback_boundary_policy must freeze rollback safety to the open reader window",
    )
    ensure(
        properties["fail_forward_policy"].get("const")
        == "FAIL_FORWARD_REQUIRED_AFTER_WINDOW_CLOSE_OR_BREAKING_CONTRACT",
        "schema_reader_window_contract.fail_forward_policy must freeze fail-forward posture after closure",
    )
    ensure(
        properties["replay_restore_policy"].get("const")
        == "RESTORE_AND_REPLAY_REQUIRE_WINDOW_COMPATIBLE_READER",
        "schema_reader_window_contract.replay_restore_policy must freeze restore/replay compatibility posture",
    )


def check_execution_mode_boundary_contract() -> None:
    schema = load_schema("execution_mode_boundary_contract.schema.json")
    ensure(
        schema["required"]
        == [
            "contract_version",
            "boundary_hash",
            "run_kind",
            "replay_class_or_null",
            "execution_mode",
            "analysis_only",
            "non_compliance_config_refs",
            "counterfactual_basis",
            "execution_posture",
            "legal_effect_boundary",
            "disclosure_reason_codes",
        ],
        "execution_mode_boundary_contract must require the full execution-mode and legal-effect boundary tuple",
    )
    ensure(
        schema.get("additionalProperties") is False,
        "execution_mode_boundary_contract must set additionalProperties=false",
    )
    properties = schema["properties"]
    ensure(
        properties["contract_version"].get("const") == "EXECUTION_MODE_BOUNDARY_V1",
        "execution_mode_boundary_contract.contract_version must stay EXECUTION_MODE_BOUNDARY_V1",
    )
    ensure(
        properties["run_kind"].get("enum")
        == ["INTERACTIVE", "NIGHTLY", "BACKFILL", "REPLAY", "REMEDIATION", "AMENDMENT", "MIGRATION"],
        "execution_mode_boundary_contract.run_kind must stay aligned to the shared run-kind vocabulary",
    )
    ensure(
        properties["execution_mode"].get("enum") == ["COMPLIANCE", "ANALYSIS"],
        "execution_mode_boundary_contract.execution_mode must stay aligned to the shared execution-mode vocabulary",
    )
    ensure(
        properties["execution_posture"].get("enum")
        == ["LIVE_COMPLIANCE", "LIVE_ANALYSIS", "REPLAY_COMPLIANCE", "REPLAY_COUNTERFACTUAL"],
        "execution_mode_boundary_contract.execution_posture must preserve the four durable live-vs-modeled postures",
    )
    ensure(
        properties["legal_effect_boundary"].get("enum")
        == [
            "COMPLIANCE_CAPABLE",
            "MODELED_READ_ONLY",
            "HISTORICAL_REPLAY_READ_ONLY",
            "COUNTERFACTUAL_REPLAY_READ_ONLY",
        ],
        "execution_mode_boundary_contract.legal_effect_boundary must preserve the live-vs-read-only consequence boundary vocabulary",
    )
    ensure(
        properties["non_compliance_config_refs"]["items"].get("minLength") == 1
        and properties["non_compliance_config_refs"].get("uniqueItems") is True
        and properties["disclosure_reason_codes"]["items"].get("minLength") == 1
        and properties["disclosure_reason_codes"].get("uniqueItems") is True,
        "execution_mode_boundary_contract arrays must reject empty strings and duplicates",
    )

    compliance_rule = find_rule_by_const(schema["allOf"], "execution_mode", "COMPLIANCE")
    ensure(compliance_rule is not None, "execution_mode_boundary_contract missing COMPLIANCE reverse guard")
    compliance_then = compliance_rule["then"]["properties"]
    ensure(
        compliance_then["analysis_only"].get("const") is False
        and compliance_then["non_compliance_config_refs"].get("maxItems") == 0
        and compliance_then["counterfactual_basis"].get("type") == "null",
        "execution_mode_boundary_contract execution_mode=COMPLIANCE must clear analysis-only markers",
    )

    analysis_rule = find_rule_by_const(schema["allOf"], "execution_mode", "ANALYSIS")
    ensure(analysis_rule is not None, "execution_mode_boundary_contract missing ANALYSIS reverse guard")
    analysis_then = analysis_rule["then"]["properties"]
    ensure(
        analysis_then["analysis_only"].get("const") is True
        and analysis_then["counterfactual_basis"].get("type") == "string",
        "execution_mode_boundary_contract execution_mode=ANALYSIS must require analysis-only posture and declared modeled basis",
    )

    replay_rule = find_rule_by_const(schema["allOf"], "run_kind", "REPLAY")
    ensure(replay_rule is not None, "execution_mode_boundary_contract missing run_kind=REPLAY guard")
    ensure(
        replay_rule["then"]["properties"]["replay_class_or_null"].get("enum")
        == ["STANDARD_REPLAY", "AUDIT_REPLAY", "COUNTERFACTUAL_ANALYSIS"],
        "execution_mode_boundary_contract run_kind=REPLAY must require an explicit replay class",
    )

    replay_compliance_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("run_kind", {}).get("const") == "REPLAY"
            and rule.get("if", {}).get("properties", {}).get("replay_class_or_null", {}).get("enum")
            == ["STANDARD_REPLAY", "AUDIT_REPLAY"]
        ),
        None,
    )
    ensure(
        replay_compliance_rule is not None,
        "execution_mode_boundary_contract missing standard/audit replay compliance guard",
    )
    replay_compliance_then = replay_compliance_rule["then"]["properties"]
    ensure(
        replay_compliance_then["execution_mode"].get("const") == "COMPLIANCE"
        and replay_compliance_then["execution_posture"].get("const") == "REPLAY_COMPLIANCE"
        and replay_compliance_then["legal_effect_boundary"].get("const")
        == "HISTORICAL_REPLAY_READ_ONLY",
        "execution_mode_boundary_contract standard/audit replay must stay replay-compliance and read-only",
    )

    counterfactual_replay_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("run_kind", {}).get("const") == "REPLAY"
            and rule.get("if", {}).get("properties", {}).get("replay_class_or_null", {}).get("const")
            == "COUNTERFACTUAL_ANALYSIS"
        ),
        None,
    )
    ensure(
        counterfactual_replay_rule is not None,
        "execution_mode_boundary_contract missing counterfactual replay guard",
    )
    counterfactual_replay_then = counterfactual_replay_rule["then"]["properties"]
    ensure(
        counterfactual_replay_then["execution_mode"].get("const") == "ANALYSIS"
        and counterfactual_replay_then["execution_posture"].get("const") == "REPLAY_COUNTERFACTUAL"
        and counterfactual_replay_then["legal_effect_boundary"].get("const")
        == "COUNTERFACTUAL_REPLAY_READ_ONLY",
        "execution_mode_boundary_contract counterfactual replay must stay analysis posture and counterfactual read-only",
    )


