    stale_rebase_rule = find_rule_by_const(defs["harnessCase"]["allOf"], "scenario_code", "STALE_REQUEST_REBASE")
    ensure(stale_rebase_rule is not None, "upload_session_recovery_harness missing stale-request-rebase guard")
    ensure(
        stale_rebase_rule["then"]["properties"]["expected_request_completion_state"].get("const")
        == "NOT_READY_STALE_RECONFIRM_REQUIRED"
        and stale_rebase_rule["then"]["properties"]["post_request_projection"]["properties"][
            "current_request_upload_ref_or_null"
        ].get("type")
        == "null",
        "upload_session_recovery_harness stale-request-rebase cases must fail closed on current-request attachment posture",
    )
    attachment_confirmation_rule = find_rule_by_const(
        defs["harnessCase"]["allOf"],
        "scenario_code",
        "ATTACHMENT_CONFIRMATION",
    )
    ensure(
        attachment_confirmation_rule is not None,
        "upload_session_recovery_harness missing attachment-confirmation guard",
    )
    ensure(
        attachment_confirmation_rule["then"]["properties"]["expected_request_completion_state"].get("const")
        == "READY_CURRENT_REQUEST_SATISFIED",
        "upload_session_recovery_harness attachment-confirmation cases must end in ready current-request satisfaction",
    )
    cross_device_rule = find_rule_by_const(
        defs["harnessCase"]["allOf"],
        "scenario_code",
        "CROSS_DEVICE_CONTINUATION",
    )
    ensure(
        cross_device_rule is not None,
        "upload_session_recovery_harness missing cross-device continuation guard",
    )
    ensure(
        cross_device_rule["then"]["properties"]["expected_request_completion_state"].get("const")
        == "NOT_READY_BYTES_IN_FLIGHT",
        "upload_session_recovery_harness cross-device continuation cases must remain in-flight rather than completed",
    )


