    ensure(
        properties["boundary_scope"].get("enum")
        == [
            "AUDIT_INVESTIGATION_FRAME",
            "CLIENT_DOCUMENT_REQUEST",
            "CLIENT_APPROVAL_PACK",
            "ENQUIRY_PACK",
            "AUTHORITY_LINK_HANDOFF",
        ],
        "externalization_governance_contract.boundary_scope must freeze the shared externalization surface vocabulary",
    )
    ensure(
        properties["shell_family_or_null"].get("enum")
        == ["CLIENT_PORTAL_SHELL", "GOVERNANCE_DENSITY_SHELL", None],
        "externalization_governance_contract.shell_family_or_null must freeze the governed shell vocabulary plus null for non-shell explanation exports",
    )
    for field in [
        "tenant_id",
        "context_anchor_ref",
        "slice_binding_ref",
        "delivery_binding_hash",
    ]:
        ensure(
            properties[field].get("minLength") == 1,
            f"externalization_governance_contract.{field} must reject empty strings",
        )
    ensure(
        properties["delivery_surface_kind"].get("enum")
        == [
            "FILTERED_AUDIT_EXPORT",
            "PORTAL_DOCUMENT_DOWNLOAD",
            "PORTAL_APPROVAL_EXPORT",
            "EXPLANATION_EXPORT",
            "AUTHORITY_LINK_EXTERNAL_HANDOFF",
        ],
        "externalization_governance_contract.delivery_surface_kind must freeze the governed externalization targets",
    )
    ensure(
        properties["history_meaning_state"].get("enum")
        == [
            "ACTIVE_FILTERED_SLICE",
            "CURRENT_ONLY",
            "CURRENT_WITH_HISTORY_EXPLICIT",
            "CURRENT_DECLARATION_OR_ISSUED_RECEIPT",
            "LIMITED_EXPLANATION_EXPLICIT",
            "HANDOFF_TARGET_EXPLICIT",
        ],
        "externalization_governance_contract.history_meaning_state must freeze the current-vs-history vocabulary",
    )
    ensure(
        properties["eligibility_state"].get("enum")
        == ["READY", "MASKED_ONLY", "LIMITED_READY", "APPROVAL_REQUIRED", "BLOCKED", "PENDING_RETURN"],
        "externalization_governance_contract.eligibility_state must freeze the externalization eligibility vocabulary",
    )
    ensure(
        properties["approval_state"].get("enum")
        == ["NOT_REQUIRED", "REQUIRED_PENDING", "SATISFIED", "DENIED"],
        "externalization_governance_contract.approval_state must freeze the approval posture vocabulary",
    )
    ensure(
        properties["masking_state"].get("enum")
        == ["NONE", "CUSTOMER_SAFE_ONLY", "MASKED_EXPORT_ONLY", "LIMITED_EXPORT", "NOT_APPLICABLE"],
        "externalization_governance_contract.masking_state must freeze the masking posture vocabulary",
    )
    ensure(
        properties["limitation_state"].get("enum")
        == [
            "FULL",
            "INTEGRITY_LIMITED",
            "HISTORY_LIMITED",
            "RETENTION_LIMITED",
            "PREFLIGHT_BLOCKED",
            "POLICY_LIMITED",
            "NOT_APPLICABLE",
        ],
        "externalization_governance_contract.limitation_state must freeze the limitation vocabulary",
    )
    for field in [
        "access_binding_hash_or_null",
        "masking_posture_fingerprint_or_null",
        "visibility_cache_partition_key_or_null",
    ]:
        ensure(
            properties[field].get("type") == ["string", "null"] and properties[field].get("minLength") == 1,
            f"externalization_governance_contract.{field} must stay string-or-null with non-empty string values",
        )
    for field in [
        "preview_target_ref_or_null",
        "download_target_ref_or_null",
        "print_target_ref_or_null",
        "external_handoff_target_ref_or_null",
        "approval_requirement_token_or_null",
    ]:
        ensure(
            properties[field].get("type") == ["string", "null"] and properties[field].get("minLength") == 1,
            f"externalization_governance_contract.{field} must stay string-or-null with non-empty string values",
        )
    ensure(
        properties["blocking_context_tokens"].get("default") == []
        and properties["blocking_context_tokens"].get("uniqueItems") is True
        and properties["blocking_context_tokens"]["items"].get("minLength") == 1,
        "externalization_governance_contract.blocking_context_tokens must remain a unique non-empty token list",
    )
    for field, expected in {
        "slice_binding_policy": "ACTIVE_GOVERNED_SLICE_REQUIRED",
        "background_scope_policy": "DETACHED_BACKGROUND_SCOPE_FORBIDDEN",
        "direct_url_policy": "DIRECT_URL_BYPASS_FORBIDDEN",
        "posture_preservation_policy": "CURRENT_HISTORY_MASKING_LIMITATION_AND_APPROVAL_PRESERVED",
        "handoff_target_policy": "EXTERNAL_TARGET_AND_BLOCKING_CONTEXT_EXPLICIT",
        "reentry_validation_policy": "RETURN_AND_DELIVERY_REQUIRE_GOVERNED_REVALIDATION",
        "delivery_context_policy": "TENANT_AND_SECURITY_CONTEXT_BOUND_AT_INVOCATION",
        "signed_url_binding_policy": "SIGNED_URLS_REQUIRE_CURRENT_GOVERNED_BINDING",
        "temporary_artifact_policy": "TEMP_FILES_AND_NATIVE_PREVIEWS_REQUIRE_MATCHING_BINDING",
    }.items():
        ensure(
            properties[field].get("const") == expected,
            f"externalization_governance_contract.{field} must stay pinned to {expected}",
        )

    approval_rule = find_rule_by_const(schema["allOf"], "eligibility_state", "APPROVAL_REQUIRED")
    ensure(
        approval_rule is not None,
        "externalization_governance_contract missing APPROVAL_REQUIRED approval-token guard",
    )
    ensure(
        approval_rule["then"]["properties"]["approval_state"].get("const") == "REQUIRED_PENDING"
        and approval_rule["then"]["properties"]["approval_requirement_token_or_null"].get("type")
        == "string",
        "externalization_governance_contract APPROVAL_REQUIRED must require REQUIRED_PENDING approval state and a non-null approval token",
    )
    masked_rule = find_rule_by_const(schema["allOf"], "eligibility_state", "MASKED_ONLY")
    ensure(masked_rule is not None, "externalization_governance_contract missing MASKED_ONLY preview guard")
    ensure(
        masked_rule["then"]["properties"]["preview_target_ref_or_null"].get("type") == "string",
        "externalization_governance_contract MASKED_ONLY must retain a preview target",
    )

    for scope, expected_shell, expected_delivery in (
        ("AUDIT_INVESTIGATION_FRAME", "GOVERNANCE_DENSITY_SHELL", "FILTERED_AUDIT_EXPORT"),
        ("CLIENT_DOCUMENT_REQUEST", "CLIENT_PORTAL_SHELL", "PORTAL_DOCUMENT_DOWNLOAD"),
        ("CLIENT_APPROVAL_PACK", "CLIENT_PORTAL_SHELL", "PORTAL_APPROVAL_EXPORT"),
        ("ENQUIRY_PACK", None, "EXPLANATION_EXPORT"),
        ("AUTHORITY_LINK_HANDOFF", "GOVERNANCE_DENSITY_SHELL", "AUTHORITY_LINK_EXTERNAL_HANDOFF"),
    ):
        scope_rule = find_rule_by_const(schema["allOf"], "boundary_scope", scope)
        ensure(scope_rule is not None, f"externalization_governance_contract missing {scope} binding rule")
        ensure(
            scope_rule["then"]["properties"]["shell_family_or_null"].get("const") == expected_shell
            and scope_rule["then"]["properties"]["delivery_surface_kind"].get("const") == expected_delivery,
            f"externalization_governance_contract {scope} rule must pin the expected shell and delivery surface",
        )
    client_document_rule = find_rule_by_const(schema["allOf"], "boundary_scope", "CLIENT_DOCUMENT_REQUEST")
    ensure(client_document_rule is not None, "externalization_governance_contract missing CLIENT_DOCUMENT_REQUEST binding rule")
    ensure(
        client_document_rule["then"]["properties"]["access_binding_hash_or_null"].get("type") == "string"
        and client_document_rule["then"]["properties"]["masking_posture_fingerprint_or_null"].get("type")
        == "string"
        and client_document_rule["then"]["properties"]["visibility_cache_partition_key_or_null"].get("type")
        == "string",
        "externalization_governance_contract CLIENT_DOCUMENT_REQUEST rule must require non-null access, masking, and visibility binding mirrors",
    )


