def check_invariant_enforcement_contract() -> None:
    schema = load_schema("invariant_enforcement_contract.schema.json")
    ensure(
        schema["required"] == INVARIANT_ENFORCEMENT_REQUIRED_FIELDS,
        "invariant_enforcement_contract must require the full BE-76 fail-closed binding set",
    )
    ensure(
        schema.get("additionalProperties") is False,
        "invariant_enforcement_contract must reject undeclared properties",
    )
    properties = schema["properties"]
    ensure(
        properties["contract_version"].get("const") == "INVARIANT_ENFORCEMENT_V1",
        "invariant_enforcement_contract.contract_version must stay INVARIANT_ENFORCEMENT_V1",
    )
    ensure(
        properties["boundary_scope"].get("enum") == ["RUN_MANIFEST", "ERROR_RECORD"],
        "invariant_enforcement_contract.boundary_scope must stay limited to manifest and error boundaries",
    )
    ensure(
        properties["boundary_specific_binding_policy"].get("enum")
        == [
            "MANIFEST_RETAINS_FAIL_CLOSED_STAGE_AND_PRIMARY_ERROR_LINK",
            "ERROR_RETAINS_INVARIANT_CLASS_FAULT_CODE_AND_TERMINAL_BINDING",
        ],
        "invariant_enforcement_contract must keep the exact boundary-specific binding policies",
    )
    ensure(
        properties["invariant_failure_state"].get("enum") == ["NOT_TRIGGERED", "TRIGGERED"],
        "invariant_enforcement_contract.invariant_failure_state must stay binary and explicit",
    )
    ensure(
        properties["failure_stage_or_null"].get("enum") == ["PRESTART", "POSTSTART", None],
        "invariant_enforcement_contract.failure_stage_or_null must stay PRESTART/POSTSTART/null",
    )
    ensure(
        properties["terminal_manifest_state_or_null"].get("enum") == ["BLOCKED", "FAILED", None],
        "invariant_enforcement_contract.terminal_manifest_state_or_null must stay BLOCKED/FAILED/null",
    )
    ensure(
        properties["transition_event_code_or_null"].get("enum") == ["system_fault", None],
        "invariant_enforcement_contract.transition_event_code_or_null must stay system_fault/null",
    )
    ensure(
        properties["terminal_audit_event_type_or_null"].get("enum") == ["ManifestBlocked", "ManifestFailed", None],
        "invariant_enforcement_contract.terminal_audit_event_type_or_null must stay ManifestBlocked/ManifestFailed/null",
    )
    ensure(
        properties["typed_error_policy"].get("const")
        == "INVARIANTS_MUST_PERSIST_FAMILY_SPECIFIC_ERROR_RECORDS",
        "invariant_enforcement_contract.typed_error_policy must force family-specific durable error records",
    )
    ensure(
        properties["partial_write_policy"].get("const")
        == "NO_PARTIAL_MUTATION_OR_SIDE_EFFECT_AFTER_INVARIANT_FAILURE",
        "invariant_enforcement_contract.partial_write_policy must force no post-failure side effects",
    )
    ensure(
        properties["audit_evidence_policy"].get("const")
        == "INVARIANTS_REQUIRE_ERROR_AND_TERMINAL_AUDIT_EVIDENCE",
        "invariant_enforcement_contract.audit_evidence_policy must require durable error and terminal audit evidence",
    )
    ensure(
        properties["lifecycle_mapping_policy"].get("const")
        == "PRESTART_INVARIANTS_BLOCK_POSTSTART_INVARIANTS_FAIL",
        "invariant_enforcement_contract.lifecycle_mapping_policy must preserve prestart/poststart terminal separation",
    )
    ensure(
        properties["assertion_conversion_policy"].get("const")
        == "ASSERTIONS_AND_GENERIC_EXCEPTIONS_MUST_COLLAPSE_TO_TYPED_FAIL_CLOSED_OUTCOMES",
        "invariant_enforcement_contract.assertion_conversion_policy must reject assertion-only crash handling",
    )
    ensure(
        properties["normalization_rejection_policy"].get("const")
        == "IMPOSSIBLE_STATES_REJECTED_NEVER_NORMALIZED",
        "invariant_enforcement_contract.normalization_rejection_policy must forbid impossible-state normalization",
    )

    run_manifest_rule = find_rule_by_const(schema["allOf"], "boundary_scope", "RUN_MANIFEST")
    ensure(run_manifest_rule is not None, "invariant_enforcement_contract missing RUN_MANIFEST binding guard")
    ensure(
        run_manifest_rule["then"]["properties"]["boundary_specific_binding_policy"].get("const")
        == "MANIFEST_RETAINS_FAIL_CLOSED_STAGE_AND_PRIMARY_ERROR_LINK",
        "invariant_enforcement_contract RUN_MANIFEST must force the manifest binding policy",
    )
    error_record_rule = find_rule_by_const(schema["allOf"], "boundary_scope", "ERROR_RECORD")
    ensure(error_record_rule is not None, "invariant_enforcement_contract missing ERROR_RECORD binding guard")
    ensure(
        error_record_rule["then"]["properties"]["boundary_specific_binding_policy"].get("const")
        == "ERROR_RETAINS_INVARIANT_CLASS_FAULT_CODE_AND_TERMINAL_BINDING",
        "invariant_enforcement_contract ERROR_RECORD must force the error binding policy",
    )

    not_triggered_rule = find_rule_by_const(schema["allOf"], "invariant_failure_state", "NOT_TRIGGERED")
    ensure(not_triggered_rule is not None, "invariant_enforcement_contract missing NOT_TRIGGERED nulling guard")
    for field in [
        "invariant_class_or_null",
        "error_family_or_null",
        "error_code_or_null",
        "failure_stage_or_null",
        "terminal_manifest_state_or_null",
        "transition_event_code_or_null",
        "terminal_audit_event_type_or_null",
        "error_record_ref_or_null",
    ]:
        ensure(
            not_triggered_rule["then"]["properties"][field].get("type") == "null",
            f"invariant_enforcement_contract NOT_TRIGGERED must clear {field}",
        )

    triggered_rule = find_rule_by_const(schema["allOf"], "invariant_failure_state", "TRIGGERED")
    ensure(triggered_rule is not None, "invariant_enforcement_contract missing TRIGGERED guard")
    ensure(
        triggered_rule["then"]["properties"]["transition_event_code_or_null"].get("const") == "system_fault",
        "invariant_enforcement_contract TRIGGERED must force system_fault transition semantics",
    )
    ensure(
        triggered_rule["then"]["properties"]["error_record_ref_or_null"].get("type") == "string",
        "invariant_enforcement_contract TRIGGERED must require error_record_ref_or_null",
    )

    prestart_rule = find_rule_by_const(schema["allOf"], "failure_stage_or_null", "PRESTART")
    ensure(prestart_rule is not None, "invariant_enforcement_contract missing PRESTART terminal mapping")
    ensure(
        prestart_rule["then"]["properties"]["terminal_manifest_state_or_null"].get("const") == "BLOCKED"
        and prestart_rule["then"]["properties"]["terminal_audit_event_type_or_null"].get("const") == "ManifestBlocked",
        "invariant_enforcement_contract PRESTART must map to BLOCKED and ManifestBlocked",
    )
    poststart_rule = find_rule_by_const(schema["allOf"], "failure_stage_or_null", "POSTSTART")
    ensure(poststart_rule is not None, "invariant_enforcement_contract missing POSTSTART terminal mapping")
    ensure(
        poststart_rule["then"]["properties"]["terminal_manifest_state_or_null"].get("const") == "FAILED"
        and poststart_rule["then"]["properties"]["terminal_audit_event_type_or_null"].get("const") == "ManifestFailed",
        "invariant_enforcement_contract POSTSTART must map to FAILED and ManifestFailed",
    )

    for invariant_class, expected_codes in INVARIANT_ENFORCEMENT_ERROR_CODES_BY_CLASS.items():
        class_rule = find_rule_by_const(schema["allOf"], "invariant_class_or_null", invariant_class)
        ensure(class_rule is not None, f"invariant_enforcement_contract missing {invariant_class} mapping guard")
        ensure(
            class_rule["then"]["properties"]["error_family_or_null"].get("const")
            == INVARIANT_ENFORCEMENT_ERROR_FAMILY_BY_CLASS[invariant_class],
            f"invariant_enforcement_contract {invariant_class} must keep its fixed error-family mapping",
        )
        error_code_schema = class_rule["then"]["properties"]["error_code_or_null"]
        actual_codes = (
            [error_code_schema["const"]]
            if "const" in error_code_schema
            else error_code_schema.get("enum")
        )
        ensure(
            actual_codes == expected_codes,
            f"invariant_enforcement_contract {invariant_class} must keep error_code_or_null in {expected_codes}",
        )


