def check_upload_request_binding_contract() -> None:
    schema = load_schema("upload_request_binding_contract.schema.json")
    ensure(
        schema["required"]
        == [
            "contract_version",
            "frozen_tenant_id",
            "frozen_client_id",
            "frozen_request_id",
            "request_identity_ref",
            "frozen_request_version_ref",
            "live_request_version_ref",
            "request_binding_state",
            "binding_resolution_basis",
            "resume_identity_policy",
            "duplicate_session_policy",
            "duplicate_file_policy",
            "inflight_rebase_policy",
            "stale_completion_policy",
            "attachment_authority_policy",
            "next_action_authority_policy",
            "cross_device_resume_policy",
            "frozen_binding_scope_hash",
            "rebase_detected_at_or_null",
        ],
        "upload_request_binding_contract must require the full upload binding and rebase field set",
    )
    ensure(
        schema.get("additionalProperties") is False,
        "upload_request_binding_contract must stay closed to ungoverned fields",
    )
    properties = schema["properties"]
    for field in [
        "frozen_tenant_id",
        "frozen_client_id",
        "frozen_request_id",
        "request_identity_ref",
        "frozen_request_version_ref",
        "live_request_version_ref",
        "frozen_binding_scope_hash",
    ]:
        ensure(
            properties[field].get("minLength") == 1,
            f"upload_request_binding_contract.{field} must reject empty strings",
        )
    ensure(
        properties["contract_version"].get("const") == "UPLOAD_REQUEST_BINDING_V1",
        "upload_request_binding_contract.contract_version must stay pinned to UPLOAD_REQUEST_BINDING_V1",
    )
    ensure(
        properties["request_binding_state"].get("enum")
        == [
            "ORIGINAL_CURRENT",
            "RECONFIRMED_CURRENT",
            "RECONFIRMATION_REQUIRED",
            "SUPERSEDED",
        ],
        "upload_request_binding_contract.request_binding_state must freeze the governed upload binding vocabulary",
    )
    ensure(
        properties["binding_resolution_basis"].get("enum")
        == [
            "ORIGINAL_FROZEN_REQUEST",
            "EXPLICIT_RECONFIRMATION",
            "ACTIVE_REQUEST_REBASE_PENDING_CONFIRMATION",
            "ACTIVE_REQUEST_SUPERSEDED",
        ],
        "upload_request_binding_contract.binding_resolution_basis must freeze the governed binding-resolution vocabulary",
    )
    for field, expected in {
        "resume_identity_policy": "RESUME_EXISTING_SESSION_ONLY",
        "duplicate_session_policy": "NO_DUPLICATE_SESSION_ON_RECONNECT",
        "duplicate_file_policy": "REUSE_FROZEN_STORAGE_REF_ON_RESUME_OR_RETRY",
        "inflight_rebase_policy": "IN_FLIGHT_REBASE_PRESERVES_SESSION_UNTIL_TRANSFER_TERMINATES",
        "stale_completion_policy": "STALE_BYTES_NEVER_SATISFY_CURRENT_REQUEST",
        "attachment_authority_policy": "ATTACH_ONLY_TO_CURRENT_OR_RECONFIRMED_REQUEST",
        "next_action_authority_policy": "TRANSFER_AND_BINDING_STATE_DETERMINE_NEXT_ACTION",
        "cross_device_resume_policy": "CROSS_DEVICE_RESUME_REUSES_EXISTING_SESSION",
    }.items():
        ensure(
            properties[field].get("const") == expected,
            f"upload_request_binding_contract.{field} must stay pinned to {expected}",
        )
    ensure(
        properties["rebase_detected_at_or_null"].get("type") == ["string", "null"],
        "upload_request_binding_contract.rebase_detected_at_or_null must stay string-or-null",
    )
    original_rule = find_rule_by_const(schema["allOf"], "request_binding_state", "ORIGINAL_CURRENT")
    ensure(original_rule is not None, "upload_request_binding_contract missing ORIGINAL_CURRENT guard")
    ensure(
        original_rule["then"]["properties"]["binding_resolution_basis"].get("const")
        == "ORIGINAL_FROZEN_REQUEST"
        and original_rule["then"]["properties"]["rebase_detected_at_or_null"].get("type") == "null",
        "upload_request_binding_contract ORIGINAL_CURRENT must keep original-frozen basis and null rebase timestamp",
    )
    reconfirmed_rule = find_rule_by_const(schema["allOf"], "request_binding_state", "RECONFIRMED_CURRENT")
    ensure(reconfirmed_rule is not None, "upload_request_binding_contract missing RECONFIRMED_CURRENT guard")
    ensure(
        reconfirmed_rule["then"]["properties"]["binding_resolution_basis"].get("const")
        == "EXPLICIT_RECONFIRMATION"
        and reconfirmed_rule["then"]["properties"]["rebase_detected_at_or_null"].get("type") == "string",
        "upload_request_binding_contract RECONFIRMED_CURRENT must require explicit reconfirmation basis and non-null rebase timestamp",
    )
    reconfirm_required_rule = find_rule_by_const(schema["allOf"], "request_binding_state", "RECONFIRMATION_REQUIRED")
    ensure(
        reconfirm_required_rule is not None,
        "upload_request_binding_contract missing RECONFIRMATION_REQUIRED guard",
    )
    ensure(
        reconfirm_required_rule["then"]["properties"]["binding_resolution_basis"].get("const")
        == "ACTIVE_REQUEST_REBASE_PENDING_CONFIRMATION"
        and reconfirm_required_rule["then"]["properties"]["rebase_detected_at_or_null"].get("type")
        == "string",
        "upload_request_binding_contract RECONFIRMATION_REQUIRED must require pending-confirmation basis and non-null rebase timestamp",
    )
    superseded_rule = find_rule_by_const(schema["allOf"], "request_binding_state", "SUPERSEDED")
    ensure(superseded_rule is not None, "upload_request_binding_contract missing SUPERSEDED guard")
    ensure(
        superseded_rule["then"]["properties"]["binding_resolution_basis"].get("const")
        == "ACTIVE_REQUEST_SUPERSEDED"
        and superseded_rule["then"]["properties"]["rebase_detected_at_or_null"].get("type") == "string",
        "upload_request_binding_contract SUPERSEDED must require superseded basis and non-null rebase timestamp",
    )


