    properties = schema["properties"]
    ensure(
        properties["contract_version"].get("const") == "GOVERNANCE_MUTATION_HAZARD_CONTRACT_V1",
        "governance_mutation_hazard_contract.contract_version must stay pinned to GOVERNANCE_MUTATION_HAZARD_CONTRACT_V1",
    )
    ensure(
        properties["count_class_profile_code"].get("const") == "GOVERNANCE_IMPACT_COUNT_CLASS_V1",
        "governance_mutation_hazard_contract.count_class_profile_code must stay pinned to GOVERNANCE_IMPACT_COUNT_CLASS_V1",
    )
    for field in [
        "hazard_contract_hash",
        "policy_snapshot_hash",
        "access_binding_hash",
        "dependency_topology_hash",
        "simulation_basis_hash",
    ]:
        ensure(
            properties[field].get("minLength") == 1,
            f"governance_mutation_hazard_contract.{field} must reject empty strings",
        )
    ensure(
        properties["commit_authority_posture"].get("enum")
        == ["PREVIEW_ONLY", "APPROVAL_GATED", "BOUNDED_SAFE"],
        "governance_mutation_hazard_contract.commit_authority_posture must freeze the preview/approval/bounded-safe vocabulary",
    )
    ensure(
        schema["$defs"]["impactedCountClass"].get("enum")
        == ["ZERO", "ONE", "SMALL_BATCH", "MEDIUM_BATCH", "LARGE_BATCH", "ESTATE_WIDE"],
        "governance_mutation_hazard_contract impacted-count classes must stay pinned to the shared bucket vocabulary",
    )
    for field in [
        "impacted_principal_count_class",
        "impacted_client_count_class",
        "impacted_authority_operation_count_class",
        "impacted_workflow_count_class",
        "impacted_limitation_count_class",
    ]:
        ensure(
            properties[field].get("$ref") == "#/$defs/impactedCountClass",
            f"governance_mutation_hazard_contract.{field} must reuse the shared impactedCountClass enum",
        )
    for field in [
        "impact_radius_lower_score",
        "impact_radius_upper_score",
        "privilege_gain_score",
        "scope_expansion_score",
        "masking_relaxation_score",
        "policy_risk_score",
        "approval_necessity_score",
        "simulation_confidence_score",
        "predictability_score",
    ]:
        ensure(
            properties[field].get("minimum") == 0 and properties[field].get("maximum") == 100,
            f"governance_mutation_hazard_contract.{field} must stay inside [0,100]",
        )
    for field in [
        "impacted_principal_count",
        "impacted_client_count",
        "impacted_authority_operation_count",
        "impacted_workflow_count",
        "impacted_limitation_count",
    ]:
        ensure(
            properties[field].get("minimum") == 0,
            f"governance_mutation_hazard_contract.{field} must stay non-negative",
        )
    ensure(
        properties["bounded_safe_mutation"].get("enum") == [0, 1],
        "governance_mutation_hazard_contract.bounded_safe_mutation must stay binary",
    )
    ensure(
        properties["approval_requirement"].get("enum")
        == [
            "NOT_REQUIRED",
            "SINGLE_APPROVER",
            "DUAL_APPROVER",
            "SECURITY_REVIEW",
            "CHANGE_ADVISORY_QUORUM",
        ],
        "governance_mutation_hazard_contract.approval_requirement must freeze the approval posture vocabulary",
    )
    ensure(
        properties["required_approvals"].get("uniqueItems") is True
        and properties["required_approvals"]["items"].get("minLength") == 1,
        "governance_mutation_hazard_contract.required_approvals must remain a unique non-empty-string list",
    )
    ensure(
        schema["$defs"]["riskDriverCode"].get("enum")
        == [
            "PRIVILEGE_GAIN",
            "SCOPE_EXPANSION",
            "MASKING_RELAXATION",
            "BROAD_BLAST_RADIUS",
        ],
        "governance_mutation_hazard_contract risk-driver vocabulary must stay complete",
    )
    ensure(
        schema["$defs"]["approvalTriggerCode"].get("enum")
        == [
            "SINGLE_APPROVER_REQUIRED",
            "DUAL_APPROVER_REQUIRED",
            "SECURITY_REVIEW_REQUIRED",
            "CHANGE_ADVISORY_QUORUM_REQUIRED",
        ],
        "governance_mutation_hazard_contract approval-trigger vocabulary must stay complete",
    )
    ensure(
        schema["$defs"]["confidenceLimiterCode"].get("enum")
        == ["LOW_SIMULATION_CONFIDENCE", "LOW_PREDICTABILITY"],
        "governance_mutation_hazard_contract confidence-limiter vocabulary must stay complete",
    )
    ensure(
        schema["$defs"]["boundedSafetyBlockerCode"].get("enum")
        == [
            "PRIVILEGE_GAIN_PRESENT",
            "SCOPE_EXPANSION_PRESENT",
            "MASKING_RELAXATION_PRESENT",
            "IMPACT_RADIUS_TOO_LARGE",
            "POLICY_RISK_TOO_HIGH",
            "CONFIDENCE_TOO_LOW",
            "PREDICTABILITY_TOO_LOW",
        ],
        "governance_mutation_hazard_contract bounded-safety blocker vocabulary must stay complete",
    )

    bounded_safe_rule = find_rule_by_const(schema["allOf"], "bounded_safe_mutation", 1)
    ensure(
        bounded_safe_rule is not None,
        "governance_mutation_hazard_contract missing bounded_safe_mutation=1 reverse guard",
    )
    ensure(
        bounded_safe_rule["then"]["properties"]["approval_requirement"].get("const") == "NOT_REQUIRED"
        and bounded_safe_rule["then"]["properties"]["commit_authority_posture"].get("const")
        == "BOUNDED_SAFE"
        and bounded_safe_rule["then"]["properties"]["required_approvals"].get("maxItems") == 0
        and bounded_safe_rule["then"]["properties"]["approval_trigger_codes"].get("maxItems") == 0
        and bounded_safe_rule["then"]["properties"]["confidence_limiter_codes"].get("maxItems") == 0
        and bounded_safe_rule["then"]["properties"]["bounded_safety_blocker_codes"].get("maxItems") == 0,
        "governance_mutation_hazard_contract bounded_safe_mutation=1 must force no-approval bounded-safe posture and clear structured blocker arrays",
    )
    non_safe_rule = find_rule_by_const(schema["allOf"], "bounded_safe_mutation", 0)
    ensure(
        non_safe_rule is not None,
        "governance_mutation_hazard_contract missing bounded_safe_mutation=0 reverse guard",
    )
    ensure(
        non_safe_rule["then"]["properties"]["approval_requirement"].get("enum")
        == ["SINGLE_APPROVER", "DUAL_APPROVER", "SECURITY_REVIEW", "CHANGE_ADVISORY_QUORUM"]
        and non_safe_rule["then"]["properties"]["required_approvals"].get("minItems") == 1
        and non_safe_rule["then"]["properties"]["bounded_safety_blocker_codes"].get("minItems") == 1,
        "governance_mutation_hazard_contract bounded_safe_mutation=0 must force concrete approval posture, non-empty approvals, and explicit blocker codes",
    )
    not_required_rule = find_rule_by_const(schema["allOf"], "approval_requirement", "NOT_REQUIRED")
    ensure(
        not_required_rule is not None,
        "governance_mutation_hazard_contract missing approval_requirement=NOT_REQUIRED reverse guard",
    )
    ensure(
        not_required_rule["then"]["properties"]["bounded_safe_mutation"].get("const") == 1,
        "governance_mutation_hazard_contract approval_requirement=NOT_REQUIRED must force bounded_safe_mutation=1",
    )
    preview_rule = find_rule_by_const(schema["allOf"], "commit_authority_posture", "PREVIEW_ONLY")
    ensure(
        preview_rule is not None,
        "governance_mutation_hazard_contract missing PREVIEW_ONLY reverse guard",
    )
    ensure(
        preview_rule["then"]["properties"]["bounded_safe_mutation"].get("const") == 0
        and preview_rule["then"]["properties"]["confidence_limiter_codes"].get("minItems") == 1,
        "governance_mutation_hazard_contract PREVIEW_ONLY must force bounded_safe_mutation=0 and explicit confidence limiters",
    )
    approval_gated_rule = find_rule_by_const(schema["allOf"], "commit_authority_posture", "APPROVAL_GATED")
    ensure(
        approval_gated_rule is not None,
        "governance_mutation_hazard_contract missing APPROVAL_GATED reverse guard",
    )
    ensure(
        approval_gated_rule["then"]["properties"]["simulation_confidence_score"].get("minimum") == 80
        and approval_gated_rule["then"]["properties"]["predictability_score"].get("minimum") == 75
        and approval_gated_rule["then"]["properties"]["bounded_safe_mutation"].get("const") == 0
        and approval_gated_rule["then"]["properties"]["approval_trigger_codes"].get("minItems") == 1,
        "governance_mutation_hazard_contract APPROVAL_GATED must require strong confidence/predictability, bounded_safe_mutation=0, and explicit approval-trigger codes",
    )
    bounded_safe_posture_rule = find_rule_by_const(schema["allOf"], "commit_authority_posture", "BOUNDED_SAFE")
    ensure(
        bounded_safe_posture_rule is not None,
        "governance_mutation_hazard_contract missing BOUNDED_SAFE reverse guard",
    )
    ensure(
        bounded_safe_posture_rule["then"]["properties"]["simulation_confidence_score"].get("minimum") == 80
        and bounded_safe_posture_rule["then"]["properties"]["predictability_score"].get("minimum") == 75
        and bounded_safe_posture_rule["then"]["properties"]["bounded_safe_mutation"].get("const") == 1
        and bounded_safe_posture_rule["then"]["properties"]["approval_requirement"].get("const")
        == "NOT_REQUIRED"
        and bounded_safe_posture_rule["then"]["properties"]["required_approvals"].get("maxItems") == 0,
        "governance_mutation_hazard_contract BOUNDED_SAFE must require strong confidence/predictability, bounded-safe posture, and no approval list",
    )


