def check_calculation_basis() -> None:
    schema = load_schema("calculation_basis.schema.json")
    check_min_length_fields(
        schema,
        [
            "calculation_basis_id",
            "calculation_id",
            "calculation_request_ref",
            "manifest_id",
            "basis_type",
            "basis_payload_ref",
            "basis_hash",
        ],
        "calculation_basis",
    )
    for field in ["user_confirmation_ref"]:
        ensure(
            schema["properties"][field].get("minLength") == 1,
            f"calculation_basis.{field} must reject empty strings when present",
        )
    ensure(
        schema["properties"]["reason_codes"]["items"].get("minLength") == 1,
        "calculation_basis.reason_codes items must reject empty strings",
    )

    for status in ["PROVISIONAL", "REJECTED", "SUPERSEDED"]:
        status_rule = find_rule_by_const(schema["allOf"], "basis_status", status)
        ensure(status_rule is not None, f"calculation_basis missing basis_status={status} guard")
        ensure(
            status_rule["then"]["properties"]["parity_reusable"].get("const") is False,
            f"calculation_basis basis_status={status} must force parity_reusable=false",
        )
        ensure(
            status_rule["then"]["properties"]["filing_reusable"].get("const") is False,
            f"calculation_basis basis_status={status} must force filing_reusable=false",
        )

    confirmed_rule = find_rule_by_const(schema["allOf"], "basis_status", "CONFIRMED")
    ensure(confirmed_rule is not None, "calculation_basis missing basis_status=CONFIRMED guard")
    ensure(
        "anyOf" in confirmed_rule["then"],
        "calculation_basis CONFIRMED must require at least one reusable flag",
    )

    reusable_rule = next(
        (
            candidate
            for candidate in schema["allOf"]
            if candidate.get("if", {}).get("anyOf")
            and candidate.get("then", {}).get("properties", {}).get("basis_status", {}).get("const") == "CONFIRMED"
        ),
        None,
    )
    ensure(reusable_rule is not None, "calculation_basis missing reusable reverse guard")

    superseded_at_rule = next(
        (
            candidate
            for candidate in schema["allOf"]
            if candidate.get("if", {}).get("properties", {}).get("superseded_at", {}).get("type") == "string"
        ),
        None,
    )
    ensure(superseded_at_rule is not None, "calculation_basis missing superseded_at reverse guard")
    ensure(
        superseded_at_rule["then"]["properties"]["basis_status"].get("const") == "SUPERSEDED",
        "calculation_basis non-null superseded_at must force basis_status=SUPERSEDED",
    )

    confirmation_ref_rule = next(
        (
            candidate
            for candidate in schema["allOf"]
            if candidate.get("if", {}).get("properties", {}).get("user_confirmation_ref", {}).get("type") == "string"
        ),
        None,
    )
    ensure(confirmation_ref_rule is not None, "calculation_basis missing user_confirmation_ref reverse guard")
    ensure(
        confirmation_ref_rule["then"]["properties"]["basis_status"].get("enum") == ["CONFIRMED", "SUPERSEDED"],
        "calculation_basis non-null user_confirmation_ref must force confirmed-or-superseded basis posture",
    )


