def check_input_freeze() -> None:
    schema = load_schema("input_freeze.schema.json")
    for field in [
        "source_plan_hash",
        "collection_boundary_hash",
        "input_policy_ref",
        "source_window_hash",
        "provider_environment_refs",
        "provider_api_versions",
        "provider_schema_versions",
        "connector_profile_ref",
        "connector_build_id",
        "cursor_checkpoint_refs",
        "request_audit_refs",
        "exclusion_refs",
        "no_data_confirmed_declarations",
        "missing_source_declarations",
        "stale_source_declarations",
        "source_domain_postures",
        "input_consumption_mode",
        "late_data_adoption_policy",
    ]:
        ensure(field in schema["required"], f"input_freeze must require `{field}`.")
    for field in [
        "source_plan_hash",
        "collection_boundary_hash",
        "input_policy_ref",
        "source_window_hash",
        "connector_profile_ref",
        "connector_build_id",
        "normalization_context_ref",
        "normalization_context_hash",
        "artifact_contract_hash",
        "input_set_hash",
    ]:
        ensure(
            schema["properties"][field].get("minLength") == 1,
            f"input_freeze.{field} must reject empty strings",
        )
    for field in [
        "provider_environment_refs",
        "provider_api_versions",
        "provider_schema_versions",
        "cursor_checkpoint_refs",
        "request_audit_refs",
        "source_record_refs",
        "evidence_item_refs",
        "candidate_fact_refs",
        "canonical_fact_refs",
        "conflict_refs",
        "exclusion_refs",
        "no_data_confirmed_declarations",
        "missing_source_declarations",
        "stale_source_declarations",
        "artifact_contract_refs",
    ]:
        ensure(
            schema["properties"][field]["items"].get("minLength") == 1,
            f"input_freeze.{field} items must reject empty strings",
        )
    ensure(
        schema["properties"]["artifact_contract_refs"].get("minItems") == 10,
        "input_freeze.artifact_contract_refs must require the full 10-ref intake pack",
    )
    ensure(
        schema["properties"]["input_consumption_mode"].get("const") == "FROZEN_INPUT_ONLY",
        "input_freeze.input_consumption_mode must stay FROZEN_INPUT_ONLY",
    )
    ensure(
        schema["properties"]["late_data_adoption_policy"].get("const") == "CHILD_REVIEW_OR_EXCLUDE_ONLY",
        "input_freeze.late_data_adoption_policy must stay CHILD_REVIEW_OR_EXCLUDE_ONLY",
    )
    ensure(
        schema["properties"]["source_domain_postures"].get("minItems") == 1,
        "input_freeze.source_domain_postures must require explicit per-domain accounting",
    )
    posture = schema["$defs"]["sourceDomainPosture"]
    for field in [
        "source_domain",
        "source_class",
        "partition_scope_refs",
        "runtime_scope_refs",
        "boundary_disposition",
        "late_data_policy_ref",
        "source_record_count",
        "evidence_item_count",
        "candidate_fact_count",
        "canonical_fact_count",
        "conflict_count",
    ]:
        ensure(field in posture["required"], f"input_freeze.sourceDomainPosture must require `{field}`.")
    open_zero_rule = find_rule_by_const(schema["allOf"], "open_conflict_count", 0)
    ensure(open_zero_rule is not None, "input_freeze missing open_conflict_count=0 reverse guard")
    ensure(
        open_zero_rule["then"]["properties"]["resolution_frontier"].get("const") == "CLEAR",
        "input_freeze open_conflict_count=0 must force resolution_frontier=CLEAR",
    )

    monitoring_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("open_conflict_count", {}).get("minimum") == 1
            and rule.get("if", {}).get("properties", {}).get("blocking_conflict_count", {}).get("const") == 0
        ),
        None,
    )
    ensure(monitoring_rule is not None, "input_freeze missing monitoring-only reverse guard")
    ensure(
        monitoring_rule["then"]["properties"]["resolution_frontier"].get("const") == "MONITORING_ONLY",
        "input_freeze open conflicts without blocking conflicts must force MONITORING_ONLY",
    )

    blocking_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("blocking_conflict_count", {}).get("minimum") == 1
        ),
        None,
    )
    ensure(blocking_rule is not None, "input_freeze missing blocking_conflict_count reverse guard")
    ensure(
        blocking_rule["then"]["properties"]["resolution_frontier"].get("const") == "BLOCKING_PRESENT",
        "input_freeze blocking_conflict_count>0 must force BLOCKING_PRESENT",
    )

    dominant_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("dominant_blocking_class", {}).get("type") == "string"
        ),
        None,
    )
    ensure(dominant_rule is not None, "input_freeze missing dominant_blocking_class reverse guard")
    ensure(
        dominant_rule["then"]["properties"]["blocking_conflict_count"].get("minimum") == 1,
        "input_freeze non-null dominant_blocking_class must require blocking conflicts",
    )
    collected_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {})
            .get("properties", {})
            .get("source_domain_postures", {})
            .get("contains", {})
            .get("properties", {})
            .get("boundary_disposition", {})
            .get("const")
            == "IN_SCOPE_COLLECTED"
        ),
        None,
    )
    ensure(collected_rule is not None, "input_freeze missing collected-posture reverse guard")
    ensure(
        collected_rule["then"]["properties"]["source_record_refs"].get("minItems") == 1,
        "input_freeze collected source-domain posture must require non-empty source_record_refs",
    )


def check_experience_cursor() -> None:
    schema = load_schema("experience_cursor.schema.json")
    check_command_truth_boundary_contract_binding(
        schema,
        "experience_cursor",
        expected_role="READ_SIDE_PROJECTION",
        expected_authoritative_record_families=[
            "RUN_MANIFEST",
            "GATE_DECISION_RECORD",
            "WORKFLOW_ITEM",
            "AUTHORITY_INTERACTION_RECORD",
            "AUDIT_EVENT",
        ],
        expected_observable_projection_families=[],
    )
    for field in ["stability_contract", "replacement_stability_contract_or_null", "schema_compatibility_ref"]:
        ensure(
            field in schema["required"],
            f"experience_cursor must require `{field}` for grouped current and replacement marker lineage",
        )
    check_stream_recovery_contract_binding(schema, "experience_cursor")
    check_native_cache_hydration_contract_binding(
        schema,
        "experience_cursor",
        expected_scope="EXPERIENCE_CURSOR",
    )
    ensure(
        schema_uses_ref(
            schema["properties"]["stability_contract"],
            "https://taxat.dev/schemas/route_stability_contract.schema.json",
        ),
        "experience_cursor.stability_contract must stay bound to route_stability_contract.schema.json",
    )
    ensure(
        schema["properties"]["schema_compatibility_ref"].get("minLength") == 1,
        "experience_cursor.schema_compatibility_ref must reject empty strings",
    )
    ensure(
        schema["properties"]["replacement_snapshot_ref"].get("minLength") == 1,
        "experience_cursor.replacement_snapshot_ref must reject empty strings when present",
    )

    replacement_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("replacement_snapshot_ref", {}).get("type") == "string"
        ),
        None,
    )
    ensure(replacement_rule is not None, "experience_cursor missing replacement_snapshot reverse guard")
    ensure(
        replacement_rule["then"]["properties"]["cursor_state"].get("const") == "REBASED",
        "experience_cursor non-null replacement_snapshot_ref must force cursor_state=REBASED",
    )
    ensure(
        schema_uses_ref(
            replacement_rule["then"]["properties"]["replacement_stability_contract_or_null"],
            "https://taxat.dev/schemas/route_stability_contract.schema.json",
        ),
        "experience_cursor replacement snapshots must also require a replacement_stability_contract_or_null",
    )

    invalidation_live_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("invalidation_reason_code", {}).get("type") == "null"
        ),
        None,
    )
    ensure(invalidation_live_rule is not None, "experience_cursor missing null invalidation reverse guard")
    ensure(
        invalidation_live_rule["then"]["properties"]["cursor_state"].get("const") == "LIVE",
        "experience_cursor null invalidation_reason_code must force cursor_state=LIVE",
    )

    for reason, cursor_state in [
        ("CURSOR_TTL_ELAPSED", "EXPIRED"),
        ("CLIENT_CLOSED", "CLOSED"),
    ]:
        rule = find_rule_by_const(schema["allOf"], "invalidation_reason_code", reason)
        ensure(rule is not None, f"experience_cursor missing reverse guard for {reason}")
        ensure(
            rule["then"]["properties"]["cursor_state"].get("const") == cursor_state,
            f"experience_cursor invalidation_reason_code={reason} must force cursor_state={cursor_state}",
        )

    rebase_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("invalidation_reason_code", {}).get("enum")
            == ["FRAME_EPOCH_ADVANCED", "HISTORY_COMPACTED", "SHELL_STABILITY_CHANGED"]
        ),
        None,
    )
    ensure(rebase_rule is not None, "experience_cursor missing reverse rebase invalidation guard")
    ensure(
        rebase_rule["then"]["properties"]["cursor_state"].get("const") == "REBASED",
        "experience_cursor rebase invalidation reasons must force cursor_state=REBASED",
    )

    revoked_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("invalidation_reason_code", {}).get("enum")
            == [
                "SESSION_REVOKED",
                "SESSION_BINDING_CHANGED",
                "ACCESS_BINDING_CHANGED",
                "MASKING_POSTURE_CHANGED",
                "SCHEMA_INCOMPATIBLE",
                "TENANT_SWITCHED",
                "PRINCIPAL_CLASS_CHANGED",
            ]
        ),
        None,
    )
    ensure(revoked_rule is not None, "experience_cursor missing reverse revoked invalidation guard")
    ensure(
        revoked_rule["then"]["properties"]["cursor_state"].get("const") == "REVOKED",
        "experience_cursor revoked invalidation reasons must force cursor_state=REVOKED",
    )


