def check_governance_access_simulation() -> None:
    schema = load_schema("governance_access_simulation.schema.json")
    check_authority_layer_boundary_contract_binding(
        schema,
        "governance_access_simulation",
        expected_scope_class="GOVERNANCE_ACCESS_SIMULATION",
    )
    check_min_length_fields(
        schema,
        [
            "simulation_id",
            "tenant_id",
            "policy_snapshot_hash",
            "principal_context_ref",
            "resource_class",
            "action_family",
        ],
        "governance_access_simulation",
    )
    ensure(
        "authority_chain_layers" in schema["required"]
        and "simulator_posture" in schema["required"]
        and "mutation_basis_contract" in schema["required"],
        "governance_access_simulation must require authority_chain_layers, simulator_posture, and mutation_basis_contract",
    )
    ensure(
        schema["properties"]["authorization_decision"].get("$ref") == "./authorization_decision.schema.json",
        "governance_access_simulation.authorization_decision must stay bound to authorization_decision.schema.json",
    )
    ensure(
        schema["properties"]["requested_partition_scope_refs"]["items"].get("minLength") == 1,
        "governance_access_simulation.requested_partition_scope_refs items must reject empty strings",
    )
    ensure(
        schema_uses_ref(
            schema["properties"]["mutation_basis_contract"],
            "https://taxat.dev/schemas/governance_mutation_basis_contract.schema.json",
        ),
        "governance_access_simulation.mutation_basis_contract must stay bound to governance_mutation_basis_contract.schema.json",
    )
    layer_stack = schema["$defs"]["authorityChainLayerStack"]
    ensure(
        layer_stack.get("minItems") == 4 and layer_stack.get("maxItems") == 5,
        "governance_access_simulation authorityChainLayerStack must keep four required layers plus optional authority-of-record fifth layer",
    )
    prefix_items = layer_stack.get("prefixItems", [])
    expected_layer_refs = [
        "#/$defs/sessionAuthnLayer",
        "#/$defs/tenantOperationalAuthorityLayer",
        "#/$defs/clientDelegationCoverageLayer",
        "#/$defs/externalAuthorityLinkReadinessLayer",
    ]
    actual_layer_refs = [item.get("$ref") for item in prefix_items]
    ensure(
        actual_layer_refs == expected_layer_refs,
        "governance_access_simulation authorityChainLayerStack must preserve canonical layer order",
    )

    hazard = schema["$defs"]["mutationHazard"]
    ensure(
        schema_uses_ref(
            hazard,
            "https://taxat.dev/schemas/governance_mutation_hazard_contract.schema.json",
        ),
        "governance_access_simulation.mutationHazard must stay bound to governance_mutation_hazard_contract.schema.json",
    )

    read_only_rule = find_rule_by_const(schema["allOf"], "simulator_posture", "READ_ONLY_DECISION")
    ensure(
        read_only_rule is not None,
        "governance_access_simulation missing simulator_posture=READ_ONLY_DECISION reverse guard",
    )
    ensure(
        read_only_rule["then"]["properties"]["mutation_hazard"].get("type") == "null",
        "governance_access_simulation READ_ONLY_DECISION must force mutation_hazard=null",
    )
    ensure(
        read_only_rule["then"]["properties"]["mutation_basis_contract"].get("type") == "null",
        "governance_access_simulation READ_ONLY_DECISION must force mutation_basis_contract=null",
    )

    bounded_safe_rule = find_rule_by_const(schema["allOf"], "simulator_posture", "BOUNDED_SAFE")
    ensure(
        bounded_safe_rule is not None,
        "governance_access_simulation missing simulator_posture=BOUNDED_SAFE reverse guard",
    )
    ensure(
        bounded_safe_rule["then"]["properties"]["mutation_hazard"]["properties"]["bounded_safe_mutation"].get("const")
        == 1
        and schema_uses_ref(
            bounded_safe_rule["then"]["properties"]["mutation_basis_contract"],
            "https://taxat.dev/schemas/governance_mutation_basis_contract.schema.json",
        ),
        "governance_access_simulation BOUNDED_SAFE must force mutation_hazard.bounded_safe_mutation=1 and require mutation_basis_contract",
    )

    approval_gated_rule = find_rule_by_const(schema["allOf"], "simulator_posture", "APPROVAL_GATED")
    ensure(
        approval_gated_rule is not None,
        "governance_access_simulation missing simulator_posture=APPROVAL_GATED reverse guard",
    )
    ensure(
        approval_gated_rule["then"]["properties"]["mutation_hazard"]["properties"]["bounded_safe_mutation"].get("const")
        == 0
        and schema_uses_ref(
            approval_gated_rule["then"]["properties"]["mutation_basis_contract"],
            "https://taxat.dev/schemas/governance_mutation_basis_contract.schema.json",
        ),
        "governance_access_simulation APPROVAL_GATED must force mutation_hazard.bounded_safe_mutation=0 and require mutation_basis_contract",
    )

    advisory_rule = find_rule_by_const(schema["allOf"], "simulator_posture", "ADVISORY_ONLY")
    ensure(
        advisory_rule is not None,
        "governance_access_simulation missing simulator_posture=ADVISORY_ONLY reverse guard",
    )
    ensure(
        schema_uses_ref(
            advisory_rule["then"]["properties"]["mutation_basis_contract"],
            "https://taxat.dev/schemas/governance_mutation_basis_contract.schema.json",
        )
        and advisory_rule["then"]["properties"]["mutation_hazard"].get("type") == "object",
        "governance_access_simulation ADVISORY_ONLY must retain mutation_hazard and require mutation_basis_contract",
    )


def check_candidate_fact() -> None:
    schema = load_schema("candidate_fact.schema.json")
    check_min_length_fields(
        schema,
        [
            "candidate_fact_id",
            "manifest_id",
            "counterfactual_basis",
            "value_payload_ref",
            "collection_boundary_ref",
            "normalization_context_ref",
            "source_record_lineage_hash",
            "evidence_lineage_hash",
            "partition_scope",
            "candidate_identity_hash",
            "dedupe_key",
        ],
        "candidate_fact",
    )
    for field in [
        "confidence",
        "supporting_evidence_refs",
        "source_record_refs",
        "partition_scope_refs",
        "partition_isolation_state",
        "visibility_basis",
        "conflict_membership_refs",
        "promotion_readiness",
    ]:
        ensure(field in schema["required"], f"candidate_fact must require `{field}`.")
    ensure(
        schema["properties"]["confidence"].get("type") == "number",
        "candidate_fact.confidence must stay non-null numeric",
    )
    ensure(
        schema["properties"]["partition_isolation_state"].get("const") == "EXACT_SINGLE_PARTITION",
        "candidate_fact.partition_isolation_state must stay EXACT_SINGLE_PARTITION",
    )
    ensure(
        schema["properties"]["visibility_basis"].get("const") == "UNMASKED_AUTHORITATIVE_ONLY",
        "candidate_fact.visibility_basis must stay UNMASKED_AUTHORITATIVE_ONLY",
    )
    ensure(
        schema["properties"]["promotion_state"].get("enum")
        == ["CANDIDATE", "PROVISIONAL", "CONTESTED", "SUPERSEDED", "RETIRED"],
        "candidate_fact.promotion_state must exclude CANONICAL posture",
    )
    for field in [
        "non_compliance_config_refs",
        "source_record_refs",
        "supporting_evidence_refs",
        "partition_scope_refs",
        "conflict_membership_refs",
    ]:
        ensure(
            schema["properties"][field]["items"].get("minLength") == 1,
            f"candidate_fact.{field} items must reject empty strings",
        )
    ensure(
        schema["properties"]["source_record_refs"].get("minItems") == 1,
        "candidate_fact.source_record_refs must require at least one source record ref",
    )
    ensure(
        schema["properties"]["supporting_evidence_refs"].get("minItems") == 1,
        "candidate_fact.supporting_evidence_refs must require at least one evidence ref",
    )
    ensure(
        schema["properties"]["partition_scope_refs"].get("maxItems") == 1,
        "candidate_fact.partition_scope_refs must remain exact single-partition only",
    )
    promotion_readiness = schema["$defs"]["promotionReadiness"]
    for field in [
        "readiness_state",
        "conflict_set_ref",
        "resolution_frontier",
        "blocking_conflict_ids",
        "blocking_conflict_count",
        "promotion_rule_ref",
        "approved_override_ref_or_null",
        "frozen_collection_boundary_required",
        "evidence_lineage_complete",
        "visibility_safe_for_authority",
    ]:
        ensure(field in promotion_readiness["required"], f"candidate_fact.promotionReadiness must require `{field}`")
    ensure(
        promotion_readiness["properties"]["readiness_state"].get("enum")
        == ["CANDIDATE_ONLY", "PROVISIONAL_ALLOWED", "READY_FOR_CANONICAL", "CONFLICT_BLOCKED"],
        "candidate_fact.promotionReadiness.readiness_state must freeze the promotion readiness vocabulary",
    )
    ensure(
        "adjustment_binding" in schema["properties"],
        "candidate_fact must expose adjustment_binding for ADJUSTMENT_FACT scope semantics",
    )
    adjustment_rule = find_rule_by_const(schema["allOf"], "fact_family", "ADJUSTMENT_FACT")
    ensure(adjustment_rule is not None, "candidate_fact missing ADJUSTMENT_FACT adjustment-binding guard")
    ensure(
        "adjustment_binding" in adjustment_rule["then"].get("required", []),
        "candidate_fact ADJUSTMENT_FACT must require adjustment_binding",
    )
    adjustment_binding = schema["$defs"]["adjustmentBinding"]["properties"]
    ensure(
        adjustment_binding["partition_application"].get("enum") == ["EXACT_PARTITION_ONLY"],
        "candidate_fact adjustment_binding.partition_application must stay EXACT_PARTITION_ONLY",
    )
    ensure(
        adjustment_binding["analysis_mode_treatment"].get("enum")
        == ["MATCH_COMPLIANCE_BASIS", "COUNTERFACTUAL_ONLY"],
        "candidate_fact adjustment_binding.analysis_mode_treatment must keep the compliance-vs-analysis vocabulary closed",
    )


