def check_late_data_finding() -> None:
    schema = load_schema("late_data_finding.schema.json")
    ensure(
        "temporal_classification_contract" in schema["required"],
        "late_data_finding must require temporal_classification_contract",
    )
    ensure(
        schema_uses_ref(
            schema["properties"]["temporal_classification_contract"],
            "./late_data_temporal_contract.schema.json",
        ),
        "late_data_finding.temporal_classification_contract must stay bound to late_data_temporal_contract.schema.json",
    )
    superseded_rule = find_rule_by_const(schema["allOf"], "finding_state", "SUPERSEDED")
    ensure(superseded_rule is not None, "late_data_finding missing SUPERSEDED guard")
    ensure(
        superseded_rule["then"]["properties"]["active_manifest_effect"].get("const") == "NONE",
        "late_data_finding SUPERSEDED must force active_manifest_effect to NONE",
    )

    expectation_map = {
        "NOTICE": "NOTICE_ONLY",
        "MANUAL_REVIEW": "REVIEW_REQUIRED",
        "CHILD_MANIFEST_REQUIRED": "OUT_OF_SCOPE_CHILD_REQUIRED",
    }
    for severity, effect in expectation_map.items():
        rule = next(
            (
                candidate
                for candidate in schema["allOf"]
                if candidate.get("if", {}).get("properties", {}).get("severity", {}).get("const") == severity
                and candidate.get("if", {}).get("not", {}).get("properties", {}).get("finding_state", {}).get("const")
                == "SUPERSEDED"
            ),
            None,
        )
        ensure(rule is not None, f"late_data_finding missing non-superseded active-effect guard for {severity}")
        ensure(
            rule["then"]["properties"]["active_manifest_effect"].get("const") == effect,
            f"late_data_finding {severity} findings must map to {effect} until they are superseded",
        )

    retro_rule = next(
        (
            candidate
            for candidate in schema["allOf"]
            if candidate.get("if", {}).get("properties", {}).get("temporal_classification_contract", {}).get("properties", {})
            .get("retroactive_impact_required", {})
            .get("const")
            is True
        ),
        None,
    )
    ensure(retro_rule is not None, "late_data_finding missing retroactive-impact temporal-contract guard")
    ensure(
        retro_rule["then"]["properties"]["reason_codes"].get("minItems") == 1,
        "late_data_finding retroactive-impact posture must require reason_codes",
    )


