def check_parity_result() -> None:
    schema = load_schema("parity_result.schema.json")
    ensure(
        "money_profile" in schema["required"],
        "parity_result must require money_profile",
    )
    for field in [
        "parity_threshold_profile_ref",
        "comparison_set_state",
        "ordered_field_codes",
        "dominant_reason_code",
        "reason_codes",
        "temporal_propagation_event_refs",
    ]:
        ensure(field in schema["required"], f"parity_result must require {field}")
    ensure(
        schema["properties"]["temporal_propagation_event_refs"]["items"].get("minLength") == 1,
        "parity_result.temporal_propagation_event_refs items must reject empty strings",
    )
    ensure(
        schema["properties"]["money_profile"].get("$ref")
        == "./schema_bundle.schema.json#/$defs/moneyProfile",
        "parity_result.money_profile must stay bound to schema_bundle moneyProfile",
    )

    field_delta_props = schema["$defs"]["fieldDelta"]["properties"]
    for field in [
        "abs_threshold",
        "abs_floor",
        "effective_abs_floor",
        "internal_value",
        "authority_value",
        "delta_signed",
        "delta_abs",
    ]:
        ensure(
            (
                field_delta_props[field]["oneOf"][0].get("$ref")
                if "oneOf" in field_delta_props[field]
                else field_delta_props[field].get("$ref")
            )
            == "./schema_bundle.schema.json#/$defs/moneyValue",
            f"parity_result.fieldDelta.{field} must allow canonical money strings",
        )
    for field in [
        "criticality_weight",
        "abs_threshold",
        "rel_threshold",
        "abs_floor",
        "effective_abs_floor",
    ]:
        ensure(
            field in schema["$defs"]["fieldDelta"]["required"],
            f"parity_result.fieldDelta must require {field}",
        )

    comparable_rule = find_rule_by_const(schema["$defs"]["fieldDelta"]["allOf"], "comparison_input_state", "COMPARABLE")
    ensure(comparable_rule is not None, "parity_result fieldDelta missing COMPARABLE guard")
    comparable_props = comparable_rule["then"]["properties"]
    for field in ["internal_value", "authority_value", "delta_signed", "delta_abs"]:
        ensure(
            comparable_props[field].get("$ref") == "./schema_bundle.schema.json#/$defs/moneyValue",
            f"parity_result comparable {field} must require canonical money strings",
        )

    invalid_set_rule = find_rule_by_const(schema["allOf"], "comparison_set_state", "INVALID")
    ensure(invalid_set_rule is not None, "parity_result missing INVALID comparison-set guard")
    invalid_props = invalid_set_rule["then"]["properties"]
    ensure(
        invalid_props["parity_classification"].get("const") == "NOT_COMPARABLE"
        and invalid_props["parity_score"].get("const") == 0
        and invalid_props["comparison_coverage"].get("const") == 0
        and invalid_props["weighted_parity_pressure"].get("const") == 0,
        "parity_result INVALID comparison sets must fail closed as not-comparable zero-score artifacts",
    )

    valid_set_rule = find_rule_by_const(schema["allOf"], "comparison_set_state", "VALID")
    ensure(valid_set_rule is not None, "parity_result missing VALID comparison-set guard")
    ensure(
        valid_set_rule["then"]["properties"]["ordered_field_codes"].get("minItems") == 1,
        "parity_result VALID comparison sets must publish deterministic ordered_field_codes",
    )

    material_rule = find_rule_by_const(schema["allOf"], "parity_classification", "MATERIAL_DIFFERENCE")
    ensure(material_rule is not None, "parity_result missing MATERIAL_DIFFERENCE guard")
    ensure(
        material_rule["then"]["properties"]["critical_blocking_field_count"].get("const") == 0,
        "parity_result MATERIAL_DIFFERENCE must keep critical_blocking_field_count at zero",
    )

    minor_rule = find_rule_by_const(schema["allOf"], "parity_classification", "MINOR_DIFFERENCE")
    ensure(minor_rule is not None, "parity_result missing MINOR_DIFFERENCE guard")
    minor_props = minor_rule["then"]["properties"]
    ensure(
        minor_props["critical_blocking_field_count"].get("const") == 0
        and minor_props["critical_material_field_count"].get("const") == 0,
        "parity_result MINOR_DIFFERENCE must keep critical counts at zero",
    )
    ensure(
        minor_props["weighted_parity_pressure"].get("exclusiveMaximum") == 1.0,
        "parity_result MINOR_DIFFERENCE must keep weighted_parity_pressure below material threshold",
    )

    match_rule = find_rule_by_const(schema["allOf"], "parity_classification", "MATCH")
    ensure(match_rule is not None, "parity_result missing MATCH guard")
    ensure(
        match_rule["then"]["properties"]["cause_hypotheses"].get("maxItems") == 0,
        "parity_result MATCH must not retain cause_hypotheses",
    )

    formulas = load_doc("compute_parity_and_trust_formulas.md")
    ensure_doc_terms(
        formulas,
        "compute_parity_and_trust_formulas.md",
        [
            "parity_threshold_profile_ref",
            "comparison_set_state",
            "ordered_field_codes",
            "dominant_reason_code",
            "blocking_ratio_cap",
        ],
        "must define the parity threshold-edge and comparison-set contract in machine-readable terms.",
    )
    modules = load_doc("modules.md")
    ensure_doc_terms(
        modules,
        "modules.md",
        [
            "ordered_field_codes",
            "comparison_set_state",
            "dominant_reason_code",
            "not-comparable",
        ],
        "must publish parity module invariants for deterministic edge classification and fail-closed invalid sets.",
    )
    gate_logic = load_doc("exact_gate_logic_and_decision_tables.md")
    ensure_doc_terms(
        gate_logic,
        "exact_gate_logic_and_decision_tables.md",
        [
            "comparison_set_state",
            "dominant_reason_code",
            "parity_comparison_set_invalid",
        ],
        "must keep parity-gate inputs aligned with the fail-closed parity artifact contract.",
    )


