def check_proof_bundle() -> None:
    schema = load_schema("proof_bundle.schema.json")
    check_retention_limited_explainability_contract_binding(
        schema,
        "proof_bundle",
        expected_scope="PROOF_BUNDLE",
        expected_surface_role="FILING_PROOF_ARTIFACT",
        expected_surface_specific_binding_policy=(
            "PROOF_BUNDLE_RETAINS_DECISIVE_LIMITATION_AND_RETENTION_BINDING"
        ),
    )
    ensure(
        schema_uses_ref(
            schema["properties"]["proof_closure_contract"],
            "./proof_closure_contract.schema.json",
        ),
        "proof_bundle.proof_closure_contract must stay bound to proof_closure_contract.schema.json",
    )
    ensure(
        schema_uses_ref(
            schema["properties"]["partition_contract"],
            "./provenance_partition_contract.schema.json",
        ),
        "proof_bundle.partition_contract must stay bound to provenance_partition_contract.schema.json",
    )
    ensure(
        "path_ref_order" in schema["properties"]["replay_recipe"]["required"],
        "proof_bundle.replay_recipe must require path_ref_order",
    )
    ensure(
        "lineage_boundary_refs" in schema["properties"]["replay_recipe"]["required"],
        "proof_bundle.replay_recipe must require lineage_boundary_refs",
    )
    ensure(
        "rejected_path_entries" in schema["required"],
        "proof_bundle must require rejected_path_entries",
    )
    ensure(
        "limitation_notes" in schema["required"],
        "proof_bundle must require limitation_notes",
    )
    ensure(
        "staleness_dependency_refs" in schema["required"],
        "proof_bundle must require staleness_dependency_refs",
    )
    ensure(
        "temporal_propagation_event_refs" in schema["required"],
        "proof_bundle must require temporal_propagation_event_refs",
    )
    ensure(
        "manifest_refs" in schema["required"]
        and "partition_contract" in schema["required"]
        and "lineage_boundary_refs" in schema["required"]
        and "decisive_lineage_boundary_refs" in schema["required"],
        "proof_bundle must require manifest_refs, partition_contract, lineage_boundary_refs, and decisive_lineage_boundary_refs",
    )
    ensure(
        schema["properties"]["temporal_propagation_event_refs"]["items"].get("minLength") == 1,
        "proof_bundle.temporal_propagation_event_refs items must reject empty strings",
    )
    ensure(
        schema["properties"]["retention_binding"]["properties"]["limitation_behavior"].get("enum")
        == ["FULL", "LIMITED", "TOMBSTONED", "PSEUDONYMISED"],
        "proof_bundle.retention_binding.limitation_behavior must freeze the expanded retention vocabulary",
    )

    primary_path_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("primary_path_ref", {}).get("type") == "string"
        ),
        None,
    )
    ensure(primary_path_rule is not None, "proof_bundle missing primary_path_ref reverse guard")
    ensure(
        primary_path_rule["then"]["properties"]["closure_state"].get("const") == "CLOSED",
        "proof_bundle non-null primary_path_ref must force closure_state=CLOSED",
    )

    contradiction_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("contradiction_refs", {}).get("minItems") == 1
        ),
        None,
    )
    ensure(contradiction_rule is not None, "proof_bundle missing contradiction reverse guard")
    ensure(
        contradiction_rule["then"]["properties"]["support_state"].get("const") == "CONTRADICTED",
        "proof_bundle contradiction_refs must force support_state=CONTRADICTED",
    )

    stale_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("stale_reason_codes", {}).get("minItems") == 1
            and "anyOf" in rule.get("then", {})
        ),
        None,
    )
    ensure(stale_rule is not None, "proof_bundle missing stale reverse guard")
    stale_states = {
        candidate.get("properties", {}).get("support_state", {}).get("const")
        or candidate.get("properties", {}).get("lifecycle_state", {}).get("const")
        for candidate in stale_rule["then"]["anyOf"]
    }
    ensure(
        stale_states == {"STALE"},
        "proof_bundle stale_reason_codes must map back to a STALE support or lifecycle posture",
    )
    stale_dependency_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("lifecycle_state", {}).get("const") == "STALE"
        ),
        None,
    )
    ensure(stale_dependency_rule is not None, "proof_bundle missing lifecycle_state=STALE dependency guard")
    ensure(
        stale_dependency_rule["then"]["properties"]["staleness_dependency_refs"].get("minItems") == 1,
        "proof_bundle STALE lifecycle must require staleness_dependency_refs",
    )

    superseded_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("superseded_by_bundle_ref", {}).get("type") == "string"
        ),
        None,
    )
    ensure(superseded_rule is not None, "proof_bundle missing superseded reverse guard")
    ensure(
        superseded_rule["then"]["properties"]["lifecycle_state"].get("const") == "SUPERSEDED",
        "proof_bundle non-null superseded_by_bundle_ref must force lifecycle_state=SUPERSEDED",
    )

    supported_path_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("support_state", {}).get("enum")
            == ["SUPPORTED", "PARTIALLY_SUPPORTED", "CONTRADICTED", "STALE"]
        ),
        None,
    )
    ensure(
        supported_path_rule is not None,
        "proof_bundle missing non-UNSUPPORTED decisive-path guard",
    )
    ensure(
        supported_path_rule["then"]["properties"]["primary_path_ref"].get("type") == "string"
        and supported_path_rule["then"]["properties"]["decisive_path_refs"].get("minItems") == 1,
        "proof_bundle non-UNSUPPORTED states must require a primary path and non-empty decisive paths",
    )

    supported_rule = find_rule_by_const(schema["allOf"], "support_state", "SUPPORTED")
    ensure(supported_rule is not None, "proof_bundle missing SUPPORTED closure guard")
    ensure(
        supported_rule["then"]["properties"]["replay_recipe"]["properties"]["replayable"].get("const")
        is True,
        "proof_bundle SUPPORTED must force replay_recipe.replayable=true",
    )

    stale_support_rule = find_rule_by_const(schema["allOf"], "support_state", "STALE")
    ensure(stale_support_rule is not None, "proof_bundle missing STALE support guard")
    ensure(
        stale_support_rule["then"]["properties"]["closure_state"].get("const") == "OPEN",
        "proof_bundle STALE must force closure_state=OPEN",
    )
    ensure(
        stale_support_rule["then"]["properties"]["staleness_dependency_refs"].get("minItems") == 1,
        "proof_bundle STALE must force staleness_dependency_refs",
    )

    cross_manifest_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("manifest_refs", {}).get("minItems") == 2
        ),
        None,
    )
    ensure(cross_manifest_rule is not None, "proof_bundle missing cross-manifest lineage-boundary guard")
    ensure(
        cross_manifest_rule["then"]["properties"]["lineage_boundary_refs"].get("minItems") == 1,
        "proof_bundle cross-manifest bundles must require lineage_boundary_refs",
    )
    ensure(
        cross_manifest_rule["then"]["properties"]["replay_recipe"]["properties"]["lineage_boundary_refs"].get("minItems")
        == 1,
        "proof_bundle cross-manifest bundles must require replay_recipe.lineage_boundary_refs",
    )

    lineage_reverse_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("lineage_boundary_refs", {}).get("minItems") == 1
        ),
        None,
    )
    ensure(lineage_reverse_rule is not None, "proof_bundle missing lineage_boundary_refs reverse guard")
    ensure(
        lineage_reverse_rule["then"]["properties"]["manifest_refs"].get("minItems") == 2,
        "proof_bundle lineage_boundary_refs must force cross-manifest manifest_refs",
    )

    decisive_lineage_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("decisive_lineage_boundary_refs", {}).get("minItems")
            == 1
        ),
        None,
    )
    ensure(
        decisive_lineage_rule is not None,
        "proof_bundle missing decisive_lineage_boundary_refs reverse guard",
    )
    ensure(
        decisive_lineage_rule["then"]["properties"]["lineage_boundary_refs"].get("minItems") == 1,
        "proof_bundle decisive_lineage_boundary_refs must require lineage_boundary_refs",
    )

    available_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("render_refs", {}).get("properties", {}).get(
                "explanation_status", {}
            ).get("const")
            == "AVAILABLE"
        ),
        None,
    )
    ensure(available_rule is not None, "proof_bundle missing AVAILABLE explanation guard")
    ensure(
        available_rule["then"]["properties"]["retention_binding"]["properties"]["limitation_behavior"].get("const")
        == "FULL",
        "proof_bundle AVAILABLE explanation_status must force retention_binding.limitation_behavior=FULL",
    )
    ensure(
        available_rule["then"]["properties"]["limitation_notes"].get("maxItems") == 0,
        "proof_bundle AVAILABLE explanation_status must clear limitation_notes",
    )

    limited_binding_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {})
            .get("properties", {})
            .get("retention_binding", {})
            .get("properties", {})
            .get("limitation_behavior", {})
            .get("enum")
            == ["LIMITED", "TOMBSTONED", "PSEUDONYMISED"]
        ),
        None,
    )
    ensure(limited_binding_rule is not None, "proof_bundle missing retention-limited explanation guard")
    ensure(
        limited_binding_rule["then"]["properties"]["render_refs"]["properties"]["explanation_status"].get("enum")
        == ["LIMITED", "FAILED"],
        "proof_bundle limited/tombstoned/pseudonymised retention must forbid AVAILABLE explanation_status",
    )
    ensure(
        limited_binding_rule["then"]["properties"]["limitation_notes"].get("minItems") == 1,
        "proof_bundle limited/tombstoned/pseudonymised retention must require limitation_notes",
    )


