def check_twin_delta_arc() -> None:
    schema = load_schema("twin_delta_arc.schema.json")
    ensure(
        schema["properties"]["comparison_key_profile_code"].get("const") == "TWIN_KEY_V1_SHA256",
        "twin_delta_arc comparison_key_profile_code must freeze TWIN_KEY_V1_SHA256",
    )
    ensure(
        "comparability_state" in schema["required"]
        and "comparability_reason_code" in schema["required"],
        "twin_delta_arc must require comparability_state and comparability_reason_code",
    )

    for delta_class, expected_rank in [
        ("STALE_COMPARISON", 2),
        ("LIMITED_VISIBILITY", 3),
        ("REPLAY_NON_AUTHORITATIVE", 4),
        ("REJECTED_OR_REVERSED", 6),
        ("OUT_OF_BAND", 7),
    ]:
        rule = next(
            (
                candidate
                for candidate in schema["allOf"]
                if candidate.get("if", {}).get("properties", {}).get("delta_class", {}).get("const") == delta_class
                and collect_nested_properties(candidate.get("then", {})).get("delta_precedence_rank", {}).get("const")
                == expected_rank
            ),
            None,
        )
        ensure(rule is not None, f"twin_delta_arc missing {delta_class} precedence rule")

    equivalent_rule = find_rule_by_const(schema["allOf"], "delta_class", "MATCH_EQUIVALENT")
    ensure(equivalent_rule is not None, "twin_delta_arc missing MATCH_EQUIVALENT guard")
    ensure(
        equivalent_rule["then"]["properties"]["equivalence_reason_codes"].get("minItems") == 1,
        "twin_delta_arc MATCH_EQUIVALENT must require equivalence_reason_codes",
    )

    waiting_rule = find_rule_by_const(schema["allOf"], "delta_class", "ACK_PENDING")
    ensure(waiting_rule is not None, "twin_delta_arc missing ACK_PENDING comparability guard")
    ensure(
        waiting_rule["then"]["properties"]["comparability_state"].get("const") == "WAITING_ON_AUTHORITY"
        and waiting_rule["then"]["properties"]["comparability_reason_code"].get("const") == "ACK_PENDING",
        "twin_delta_arc ACK_PENDING must freeze waiting-on-authority comparability",
    )

    partial_rule = find_rule_by_const(schema["allOf"], "delta_class", "ACK_PARTIAL")
    ensure(partial_rule is not None, "twin_delta_arc missing ACK_PARTIAL comparability guard")
    ensure(
        partial_rule["then"]["properties"]["comparability_state"].get("const") == "PARTIALLY_COMPARABLE"
        and partial_rule["then"]["properties"]["comparability_reason_code"].get("const") == "ACK_PARTIAL",
        "twin_delta_arc ACK_PARTIAL must freeze partial comparability",
    )

    out_of_band_rule = find_rule_by_const(schema["allOf"], "delta_class", "OUT_OF_BAND")
    ensure(out_of_band_rule is not None, "twin_delta_arc missing OUT_OF_BAND comparability guard")
    ensure(
        out_of_band_rule["then"]["properties"]["comparability_state"].get("const") == "OUT_OF_BAND"
        and out_of_band_rule["then"]["properties"]["comparability_reason_code"].get("const")
        == "OUT_OF_BAND",
        "twin_delta_arc OUT_OF_BAND must freeze out-of-band comparability",
    )

    contradiction_rule = next(
        (
            rule
            for rule in schema["allOf"]
            if rule.get("if", {}).get("properties", {}).get("contradiction_component_refs", {}).get("minItems")
            == 1
        ),
        None,
    )
    ensure(
        contradiction_rule is not None,
        "twin_delta_arc missing contradiction_component_refs reverse guard",
    )
    ensure(
        contradiction_rule["then"]["properties"]["comparability_state"].get("const") == "CONTRADICTORY",
        "twin_delta_arc contradiction_component_refs must force comparability_state=CONTRADICTORY",
    )


