def main() -> int:
    failures = run_guard_checks()
    if failures:
        for failure in failures:
            print(f"FAIL: {failure}", file=sys.stderr)
        return 1

    print("forensic contract guard: PASS")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
